local articles = {
    { date = "Fri, 10 Jul 2026 00:00:00 GMT", title = "The Bug in the Gap", loc = "/blog/the-bug-in-the-gap", desc = "Security Review, the third and last of three Fridays on what makes a server operating system dependable, and the close of the Boring on Purpose series. When one of these surfaces finally gives, who patches it, and how fast can you trust the patch? On 1 July 2024 Qualys published regreSSHion, CVE-2024-6387, a signal-handler race in OpenSSH's server. On FreeBSD it was answered in one advisory, FreeBSD-SA-24:04, six branches corrected between 08:22:13 and 08:27:53 UTC, a window of five minutes and forty seconds; on a Linux fleet the same fix arrived as a week of separate distribution advisories, each on its own calendar. That gap between one coherent answer and a scattered one is also where the bug lived in the first place. The November 2025 runc break-outs, CVE-2025-31133, CVE-2025-52565 and CVE-2025-52881 reported by Aleksa Sarai of SUSE, swap a device file for a symlink into procfs so that runc bind-mounts a procfs target read-write; the kernel, the namespaces and the runtime were each individually correct, and the break-out lived in the seam between them, the writable procfs surface each assumed another was minding. The pattern is older than containers: in 2020 the kernel added faccessat2, in 2021 glibc 2.33 preferred it, and the default container seccomp allow-list did not permit it, so three correct decisions produced a locked door nobody ordered. CIQ engineers Sahlberg, Maple and Allison counted 4,594 known upstream-fixed bugs never back-ported into the RHEL 8.8 kernel as of May 2024. FreeBSD is not without sin either; weeks after regreSSHion it shipped CVE-2024-7589, an unauthenticated root hole in its own sshd from its own blocklistd integration. But a jail, from FreeBSD 4.0 in 2000, is one kernel object with the boundary in the syscall layer, not assembled from namespaces and cgroups and a runtime and a procfs convention read three ways, so there is no seam to slip between; and one tree, kernel and libc from the same commit, closes the faccessat2 gap and is why regreSSHion was answered in six branches inside five minutes. You do not choose your bugs; you choose your defect density, decided the day the system was designed. Boring is not the absence of engineering. It is engineering, banked early, paying out on your worst morning." },
    { date = "Wed, 08 Jul 2026 00:00:00 GMT", title = "The Layers That Hide What They Should Bound", loc = "/blog/the-layers-that-hide-what-they-should-bound", desc = "Lean Software, the fifth of eighteen Wednesdays on how we got here, and the close of the diagnosis. This week takes the fourth of the four breaks, the layers, the subtlest of them, because layering is not a mistake but one of the genuinely good ideas in the field. In 1968 Edsger Dijkstra described the THE multiprogramming system as a strict hierarchy of levels, each built only on the one below, a discipline for containing complexity so a programmer could reason about a single level and trust everything beneath it as settled. In 1972 David Parnas gave the discipline its sharpest formulation, coining the term information hiding: a module should hide a design decision that is likely to change, so the boundary is drawn where the volatility lives. Somewhere between Parnas and the cloud generation the verb changed from containing to postponing, and the promise broke both ways. The thing below keeps leaking through, the ORM's SQL in the slow-query log, the cache's staleness as the bug that cannot be reproduced, the mesh's retry as the write that landed twice; and it stopped reducing what you must know, because you now carry the layer and the thing it was supposed to spare you. There is a well-worn line, usually given to Phil Karlton and preserved by Tim Bray, that there are only two hard things in computer science, cache invalidation and naming things, and the modern stack does both at once by adding a layer. In 1974, studying IBM's OS/360, Meir Lehman set down his second law of software evolution: complexity increases unless explicit work is done to reduce it, and reduction has to be chosen and funded against every incentive, so the layers accumulate and the reduction is the work nobody is paid to do. The alternative is to bound complexity with things small enough to be understood whole and complete enough to need nothing wrapped around them. SQLite is about 156,000 lines of C shipped as a single amalgamated file, on over four billion smartphones and an estimated trillion databases in active use, bounding complexity by being finished rather than hidden. awk has done its one job since 1977, sed dates from 1974, make from 1976, and pf has been one configuration file with one coherent syntax since OpenBSD 3.0 in December 2001, refined for a quarter of a century and never replaced. A FreeBSD base is one source tree, kernel, C library, firewall and documentation built and released together, so the pieces fit because they were made to fit. Four things broke at once, the count, the boundary, the workaround and the layers, four diagnoses of one system with three carriers behind it, npm, Docker and the way we organise teams. Next Wednesday begins the second phase: npm in detail, starting with the registry that was never a service but a market." },
    { date = "Mon, 06 Jul 2026 00:00:00 GMT", title = "The Line Without the Paper", loc = "/blog/the-line-without-the-paper", desc = "Unix Universe, the second of four portraits of the Unix family, one branch per Monday. If the certified Unixes are a register of strangers who happen to share a word, the BSDs are the opposite problem, and the more interesting one: a family that forked as sharply as any, more than once out of a plain falling-out, and stayed a single thing. Fragmentation is supposed to be what forking produces, and the Linux world is the standing example, one kernel underneath several hundred distributions that agree on very little above it. The BSDs forked too and did not fragment. Four siblings came out of one Berkeley source, each with a temperament sharp enough to have caused the split. FreeBSD is the generalist, built to be depended on: Netflix serves a large share of the evening internet from FreeBSD appliances, every PlayStation runs an operating system that is FreeBSD extended with Sony's own layers on top, and Juniper has routed the world's traffic on it for a quarter of a century. Its choices are wide driver support, ZFS as a first-class citizen, the bhyve hypervisor, and jails, kernel-enforced container isolation that shipped in 2000, the same idea the industry would rediscover more than a decade later and call containers, only thinner. OpenBSD, forked from NetBSD by Theo de Raadt in October 1995, would rather be correct than popular: it audits its source by hand, continuously, and gave the world OpenSSH, LibreSSL, doas and OpenNTPD, and pf; the price of the guarantee is that it runs on less hardware and takes up new drivers slowly. NetBSD will run anywhere, targeting on the order of sixty hardware platforms across sixteen processor architectures, and its pkgsrc package tree of roughly twenty-nine thousand recipes builds the same software on illumos, macOS and Linux; the price is that it leads on none of them. DragonFly BSD, forked from FreeBSD 4.8 by Matthew Dillon in June 2003 over the kernel's multiprocessing direction, built a kernel organised around message-passing and produced the HAMMER2 filesystem. What the four share is not a certificate but the shape of the thing each inherited: a base system, in which the kernel and the core userland, the compiler, the C library, the shell, the daemons and the manual pages are one source tree, grown together, released together and audited as a single object. Fork a system built that way and you carry off a whole, not a fragment that needs a hundred other projects before it becomes usable. A Linux distribution is assembled instead, a kernel from one project, a C library from another, core utilities from a third, and several hundred more parts integrated by the distributor every release. Both ship excellent systems; they keep the whole in different places. A BSD keeps it in the tree; a distribution keeps it in the work. When the whole is kept in one tree, a disagreement can take the tree and remain whole. Next Monday: discipline without descent, the outsider that kept the rules Unix wrote, in a kernel Unix never chose." },
    { date = "Sun, 05 Jul 2026 00:00:00 GMT", title = "The Code You Did Not Write", loc = "/blog/the-code-you-did-not-write", desc = "IT Philosophy, the first of three Sundays on what we can no longer read, one layer above the silicon the previous series ended at. The scene has become a genre: at three in the morning a service is doing the wrong thing, someone runs git blame, a name appears, and the colleague it names admits they do not know why the line is the way it is, because they did not write it, they accepted it. Authorship used to be solid, and git blame was a rough but honest instrument that pointed at the mind that shaped a line; now it points at the acceptor, not the author, and cannot tell the difference. In its 2026 survey the security firm Aikido reported that only twenty-one per cent of organisations believe AI will ever write secure code without human oversight, that sixty-nine per cent have already found vulnerabilities introduced by AI-generated code, and that one organisation in five has suffered a serious incident traced to it. The deeper problem is provenance: you can read the generated line, but not where it came from, and the model that produced it cannot be forked, inspected or called to account; the industry's answer, an AI bill of materials, draws after the fact a line the architecture never drew, a label rather than a boundary. While engineers debated provenance the law settled the accountability question in two jurisdictions that agree on little: California's AB 316, a 2025 statute, bars a defendant who developed, modified or used an AI system from arguing the system autonomously caused the harm, without creating strict liability; and the European Union's revised Product Liability Directive, 2024/2853, from December 2026, writes software and AI into the definition of a product under no-fault liability and shifts the burden of proof, with the companion Cyber Resilience Act supplying the processes whose absence a court will notice. Two systems, reasoning apart, arrive at the same place: the entity that ships the code owns it, whoever or whatever first wrote it, and review is becoming a duty the law assumes you performed. The models are a genuine gain and a human can write unmaintainable code too; what is new is the rate and the plausibility. Acceptance is not authorship, and accountability does not transfer to the thing you accepted from. Next Sunday: who governs the thing you cannot fork?" },
    { date = "Fri, 03 Jul 2026 00:00:00 GMT", title = "The Program in the Kernel", loc = "/blog/the-program-in-the-kernel", desc = "Security Review, the second of three Fridays on what makes a server operating system dependable, and the difference between a capability that was planned and one that was retrofitted. eBPF lets you load a program that the kernel compiles and runs in Ring 0, and the only thing between that program and the kernel is a static analyser called the verifier, which proves it cannot touch what it should not. So its record is the record of the boundary, and that record is poor: of forty-one eBPF vulnerability classes analysed at IEEE Symposium on Security and Privacy, twenty-eight, about sixty-eight per cent, are memory-safety bugs, the exact class the verifier exists to make impossible. The cases run like a relay across nine years, from CVE-2017-16995 through the Pwn2Own-winning CVE-2020-8835 and a Kubernetes container escape to this year's CVE-2026-31413 and CVE-2026-31525, and the class did not age out; it is structural. The ecosystem's own quiet admission is that since kernel 5.13 unprivileged eBPF ships switched off by default on most distributions. The verifier keeps failing because of what it is asked: prove an arbitrary program, possibly an attacker's, safe for Ring 0, and every new helper widens what must be proved. eBPF descends from a packet filter taught to be a general machine; the capability arrived first and the containment was retrofitted. In fairness eBPF is genuinely capable, XDP at line rate, Cilium networking, observability at scale, and FreeBSD is not smug, DTrace has a privileged destructive mode of its own. But FreeBSD has had the same live trace since 2008 through DTrace, designed at Sun with the safety requirement written before the feature list, in the base system, jail-aware, its D language built with no loops and no writes by default so the dangerous program cannot be formed. One design verifies what you wrote; the other constrains what you can write. A verifier can have a bug; a missing capability cannot. Next Friday: when one of these surfaces finally gives, who patches it, and how fast can you trust the patch?" },
    { date = "Wed, 01 Jul 2026 00:00:00 GMT", title = "The Workaround That Became Architecture", loc = "/blog/the-workaround-that-became-architecture", desc = "Lean Software, the fourth of eighteen Wednesdays on how we got here, and the third of the four breaks, the one most often mistaken for good practice rather than a workaround. In November 2009 Ryan Dahl presented Node.js at JSConf EU: a single-threaded event loop with non-blocking I/O, a genuinely good answer for an I/O-bound workload. It did not stay confined to that question; within a few years Node was the default runtime for very nearly everything, and a single-threaded runtime uses one core. The workaround arrived in layers: the cluster module in 2011, one process pretending to be several, then Docker in 2013, each instance in its own container. Because the convenient way to build a container starts from a distribution base image, each carries a whole userland, its own libraries, shell and package manager, and therefore its own attack surface and patch burden; you set out to ship one process and shipped a small operating system to keep it company, then ran a zoo of them for one application. None of this was totally wrong, and on Linux it had genuine use, but Docker paid down a Linux tax that a system with a single base and one package tree, FreeBSD among them, never had. The clean test of workaround versus architecture is whether a different choice removes the need for it: Go ships a scheduler in its runtime, multiplexing goroutines across every core of one process, and Rust reaches the same through an async runtime such as Tokio, one binary, all cores. The isolation the container advertises was solved in 2000, when FreeBSD jails shipped with FreeBSD 4.0, from work by Poul-Henning Kamp, kernel-enforced, at almost no cost and to an enterprise-grade standard. Multiplied across every deployment now running, the sprawl is data centres of power spent on a workaround, at no gain in speed. Amazon Prime Video collapsed a distributed pipeline into one process and cut cost by about ninety per cent, Segment folded a hundred and forty services into one, and Istio merged its control plane into istiod. Next Wednesday: the layers that hide what they should bound." },
    { date = "Mon, 29 Jun 2026 00:00:00 GMT", title = "The Ones With the Paper", loc = "/blog/the-ones-with-the-paper", desc = "Unix Universe, the first of four portraits of the Unix family, one branch per Monday. On the last day of 2025 a certified Unix died: HP-UX 11i v3 reached end of support on 31 December, its Open Group certificate worthless once Intel's last Itanium (2021) left it nowhere to run. A certified Unix is one whose vendor paid The Open Group to be measured against the Single UNIX Specification, at UNIX 03 or the stricter UNIX V7; the mark certifies that a system speaks Unix, not that it descends from Unix or has anywhere to go. The same certificate ages five ways. HP-UX is the dead end, no open successor. Solaris is frozen, supported to 2037, but Sun's ZFS, DTrace and Zones live on as open-source illumos and its distributions OpenIndiana, OmniOS and SmartOS; the niche endured through a fork, not a contract. AIX is the one still built, the only system at UNIX V7 level, carried onto POWER11 in 2025. z/OS certifies a POSIX surface, UNIX System Services, over a 1960s MVS mainframe. And the largest carrier of all is two systems: Darwin, the open-source XNU-and-BSD core that PureDarwin can boot on its own, and macOS, the proprietary system on top that holds the UNIX 03 certificate. macOS needs Darwin; Darwin does not need macOS. The certificate is a pass to a niche, not a bond of family. Next Monday: the same lineage, minus the paper, the four BSD siblings who forked and stayed whole." },
    { date = "Sun, 28 Jun 2026 00:00:00 GMT", title = "The Last Ten Per Cent", loc = "/blog/the-last-ten-per-cent", desc = "IT Philosophy. Perfectionism, as the industry practises it, is the chase for the last ten per cent, and that last ten per cent costs more than the ninety that came before it; the polish rarely earns out because everything has a shelf-life, and the month spent perfecting a corner is gone when its span of validity ends. The word itself is a misnomer: the person who builds everything to the maximum and calls this perfectionism is not a perfectionist but its opposite, because perfect is not the maximum, it is the fit, the result proportioned exactly to what the scenario asks and no further. There is a plainer test the word fails: what nine in ten of the people who use a thing cannot even perceive without having it explained to them is, by definition, not the fit but surplus, and surplus is paid for three times over, once in the making of a refinement no one asked for, again in the explaining of a merit no one notices, and a third time in the slow attrition of the maker, who comes to feel permanently underappreciated for a value glaringly obvious to him and invisible to everyone else. This is not a defence of the cut corner: stopping at the fit is harder than stopping early, and that judgement is not a shortcut around mastery, it is mastery, simplicity and a very good level joined in years of experience. The demoscene has known it for forty years, a 4K intro rendering a whole three-dimensional world from 4,096 bytes where every byte is a decision, proof that severe constraint produces extraordinary results not despite the limitation but because of it; KISS, lean and minimal are the disciplines of removing everything that does not earn its place, so the result reaches very good reliably and is trusted for the restraint. Kintsugi, the repair of broken pottery with gold so the mend is honoured rather than hidden, gives the argument its image, distinct from the unmanaged seam of a thing no one owned, which is just rot with good lighting. And the honest limit: none of this keeps the old because it is old, an OpenSSH from the wrong year (regreSSHion, CVE-2024-6387) is a door not an heirloom, and it is no argument against rewriting a genuinely broken system; the reflex to rewrite the working thing is the failure, the decision to rewrite the broken one is judgement, and telling them apart is the same skill as knowing where the fit lies." },
    { date = "Fri, 26 Jun 2026 00:00:00 GMT", title = "The Surface You Never Added", loc = "/blog/the-surface-you-never-added", desc = "Security Review, the first of three Fridays on what makes a server operating system dependable, judged through security by the trouble it does not invite. In 2023 Google switched io_uring off: out of ChromeOS, restricted in Android, disabled on its own production servers. The reason is a number: of the Linux kernel exploits submitted to Google's bounty in 2022, about six in ten exploited io_uring, the majority of every break-in the programme was shown, from one subsystem barely three years old, and it paid roughly a million euros for that component alone. io_uring, by Jens Axboe, merged into Linux 5.1 in 2019, is an asynchronous I/O interface built on two shared-memory rings, and it is the fifth way Linux has offered to wait for input and output, after select, poll, epoll and POSIX AIO: the kernel did not replace its I/O model but accreted one. To go faster, io_uring moves asynchronous execution into the kernel across a shared region and well over a hundred opcodes, every one attack surface, and it is still producing serious holes in 2026, PinTheft (CVE-2026-43494) chaining an RDS refcount bug with io_uring for local root, and a zero-copy-receive use-after-free (CVE-2026-43174). io_uring solves a real problem and FreeBSD is no temple, but defect density is decided by process and planning. FreeBSD waits for input and output through kqueue, written by Jonathan Lemon and shipped in FreeBSD 4.1 in July 2000, one kevent interface for files, sockets, signals, timers and processes, unreplaced in twenty-six years; it notifies and gets out of the way, with no shared ring and no in-kernel opcode catalogue, so the corridor io_uring offers an attacker was never built. The safest feature is the one you never add. Next Friday: the program you let into the kernel." },
    { date = "Wed, 24 Jun 2026 00:00:00 GMT", title = "The Boundary That Was Never Drawn", loc = "/blog/the-boundary-that-was-never-drawn", desc = "Lean Software, the third of eighteen Wednesdays on how we got here. Last week took the count on its own; this week takes the second of the four breaks, the one the count quietly sets up. A node_modules directory has no responsibility line, and the security cost of that absence is one the architecture cannot fix. The instinct is to audit, read them, scan them, pin them, sign them, and as a primary defence it is mistaken, because you will not read fifteen hundred packages and neither will anyone else. Security comes instead from a responsibility line: knowing where a component lives, who is accountable for it, how it arrives on your disk and how to confirm it arrived intact. libc is the proof the line is ordinary, a known home in the base system source tree, named maintainers, numbered releases and reproducible, signed builds, for code nobody reads and everybody trusts. node_modules has none of those four, and your application code and the fifteen hundred packages run with the same permissions: a post-install script runs as you, with your shell, your SSH keys and your cloud tokens, the moment the install completes and before you have run anything. The first half of 2026 supplies a register, read in order because the mechanisms differ and the shape never does: axios with over a hundred million weekly downloads and a re-pointed latest tag carrying a cross-platform remote-access trojan; node-ipc, around 822,000 weekly downloads, taken over through the expired domain atlantis-software.net re-registered for the price of a renewal; a typosquat run of fourteen packages in four hours; a dependency-confusion campaign of thirty-three packages across nine mirrored scopes; and Miasma, thirty-two Red Hat scope packages through a hijacked pipeline carrying valid signed SLSA provenance, the signature real and the package malicious all the same. Five mechanisms in three months and one shape underneath: no responsibility line, so nothing to cross. A market sells the boundary back, Dependabot, Snyk, Socket, signed provenance, and it is not worthless and not the boundary; it bolts partial filters onto an architecture that still has none beneath them. The responsibility line is the architecture's job, and node_modules never drew one. Security here was never a reading problem; it was a boundary problem, and the boundary was never drawn. Next Wednesday: the workaround that became architecture." },
    { date = "Mon, 22 Jun 2026 00:00:00 GMT", title = "Origins of Unix", loc = "/blog/origins-of-unix", desc = "Unix Universe, the third and last of three Mondays on what Unix is. Where Unix came from. The fifty-seven-year arc reduces to four small moments between 1969 and 1994. In the late 1960s AT&T's Bell Labs withdrew from the overrun Multics project; Ken Thompson, back from that work, found a little-used DEC PDP-7 minicomputer going spare and began a much smaller system. Brian Kernighan, by his own later account, suggested calling it Unics, a pun on Multics, soon spelled Unix; Dennis Ritchie and Douglas McIlroy joined, and McIlroy contributed the design idea that became the signature: small programs that do one thing well, composed through pipes in plain text. In 1973 the system was rewritten in C, a language Ritchie had developed, and became portable, which almost nothing else of its generation was. Barred by antitrust agreement from the computer business, AT&T licensed the source to universities for a nominal fee; Version 6 (1975) spread widely, and John Lions' Commentary on the V6 kernel (1976) was photocopied for two decades. In 1977 the Computer Systems Research Group at Berkeley began distributing its own modifications as the Berkeley Software Distribution; 4.2BSD (1983) shipped the TCP/IP networking every modern operating system on the internet still uses. By the early 1980s two Unix lines circulated: AT&T's commercial System V (1983) and Berkeley's BSD, descended from the same root but diverged. Through the 1980s Unix became the workstation lingua franca (SunOS, Ultrix, AIX, HP-UX, IRIX, NeXTSTEP), the incompatibilities were the Unix wars, and IEEE POSIX (1003.1-1988) standardised the interface rather than the implementation. In 1991 Berkeley released Net/2, substantially clear of AT&T code; BSDi sold a product based on it; USL sued, and the 1994 settlement required Berkeley to remove three files and amend roughly seventy more out of some eighteen thousand, hardly the vindication AT&T's lawyers had been retained to deliver. The result, 4.4BSD-Lite, is the clean release from which FreeBSD (1993), NetBSD (1993), OpenBSD (1996) and DragonFly BSD (2003) descend, the lineage that runs on Netflix, Sony PlayStation, Juniper and inside macOS. 1991 is the year free Unix arrived, on two fronts at once. The BSD side: Net/2, then 386BSD (1992), then FreeBSD and NetBSD (1993), Unix in the full sense, descended in its own source from Bell Labs and Berkeley. The other, separate story: a Helsinki student, Linus Torvalds, had been working on MINIX, the small teaching Unix Andrew Tanenbaum wrote in 1987; he liked Unix and found MINIX too confining, kept deliberately simple and licensed too tightly to extend, so he wrote a kernel of his own from scratch, with no Bell Labs or Berkeley code in it, and paired with the GNU userland Richard Stallman's project had been building since 1983 it became GNU/Linux, reaching 1.0 in 1994, a year after FreeBSD's own. These are not two versions of one thing: the BSDs are Unix by descent, Linux is Unix-like by resemblance, a unixoid that inherited none of the code, and that it became the most widely deployed Unix-like kernel on Earth is a fact about reach, not lineage. The family that emerged has outlived the moment and is still running." },
    { date = "Sun, 21 Jun 2026 00:00:00 GMT", title = "The Layer You Cannot Fork", loc = "/blog/the-layer-you-cannot-fork", desc = "IT Philosophy, the third and last of three on European software sovereignty. The first Sunday mapped the licence layer, the second the architectural layer; this one reaches the floor they both rest on, the silicon. Below the operating system run three layers no licence reaches. The system firmware (UEFI, the modern BIOS) boots the machine; on some hardware the open coreboot can replace it, on most it cannot. The platform management firmware runs a second computer inside the first: Intel's Management Engine is a separate processor on its own MINIX-based firmware at a privilege below the kernel, active even while the machine is powered off, and through AMT it carries a network path of its own; CVE-2017-5689 showed it could be taken over remotely. AMD's Platform Security Processor is the equivalent embedded ARM core, with full system access but without that direct network path. Beneath both sits the CPU microcode, the signed and encrypted program that turns architectural instructions into the processor's internal operations; it updates only under the manufacturer's signature and cannot be read, written or forked. The instruction set itself is a question of ownership: x86 is held by Intel and AMD behind a patent thicket, two vendors in practice; ARM is owned by Japan's SoftBank and licensed core by core; RISC-V is open and anyone may implement it without a fee, but its governing body, RISC-V International, moved its incorporation to neutral Switzerland in 2020 to insulate the standard from any single state's trade policy. You can fork the specification; you cannot fork the foundry. Europe's most complex processor, SiPearl's Rhea1, taped out in 2025 for the JUPITER exascale machine, is built on licensed ARM Neoverse cores and fabricated by TSMC in Taiwan. China is pursuing the whole depth at once: a domestic instruction set in LoongArch, a domestic foundry in SMIC, which has produced the 5nm-class Kirin 9030 without the extreme-ultraviolet tools restricted to it, and, at the research frontier, a bismuth-based two-dimensional transistor reported by Peking University, a laboratory result and not a product. Europe is learning to own its software and does not yet own its silicon. Naming the floor is the most useful thing the series can do. You fork the code, not the chip. The licence was the layer with the most words; this was the layer with the fewest, and the most consequence." },
    { date = "Fri, 19 Jun 2026 00:00:00 GMT", title = "The Package That Reads Your Keys", loc = "/blog/the-package-that-reads-your-keys", desc = "Security Review, Friday 19 June 2026. Between 01:12 and 02:39 UTC on 17 June, a dormant contributor account whose publishing rights to the @mastra npm scope were never revoked republished 144 packages, each with one added dependency: easy-day-js, a typosquat of dayjs. Its postinstall hook ran a cross-platform infostealer that swept browser data, 166 cryptocurrency wallet extensions, SSH keys and cloud tokens; @mastra/core alone sees roughly 918,000 weekly installs. There is no CVE: an account takeover is not a software defect, so every CVE-bound scanner was blind, and only osv-scanner, reading open advisory data, flagged it. Sonatype tracks it as sonatype-2026-003926. The same month, Miasma republished 32 @redhat-cloud-services packages and Shai-Hulud Hades worked PyPI through a .pth file that runs whenever Python merely starts. postinstall and .pth are one decision: installing, or merely starting the interpreter, is arbitrary code execution before anyone has read a line. The BSD and Rust answer is three gates: review before the tree with curated ports and cargo-vet, verification before use with distinfo SHA256, OpenBSD signify and immutable crates.io, and isolation at execution with Capsicum, jails, pledge and unveil. pkg_add verifies before it acts, postinstall acts before anything is verified." },
    { date = "Wed, 17 Jun 2026 00:00:00 GMT", title = "The Count That Was Never Justified", loc = "/blog/the-count-that-was-never-justified", desc = "Lean Software, the second of eighteen Wednesdays on how we got here. Last week set out four things that broke at the same time in the modern web stack; this week takes the first on its own. The count: the fact that an ordinary install brings several hundred megabytes of code, a hundred-thousand-file directory and a fifteen-hundred-package transitive closure to a project that has not yet run a line. The standard reading is that the count is the cost of features: a modern application does more than the static HTML of 1998, therefore it requires more code, therefore the count is the price one pays. The argument is honest in form and, on the evidence, not true. The HTTP Archive Web Almanac 2025 Page Weight report puts the median page at 697 kilobytes of JavaScript on its home page and 632 KB on inner pages, the 90th percentile at 1,979 KB before the first character of content arrives; the 10th percentile, the lightest tenth of the public web which by definition includes pages that work, ships 87 KB. That is the floor, and it exists. HTMX, by Carson Gross, is fourteen kilobytes minified, around five gzipped, and gives full reactivity over the wire with no virtual DOM, no bundler and no node_modules. HEY and Basecamp run on Hotwire, HTML over the wire with Turbo and Stimulus. A whole tier of small libraries now works in the same order of magnitude: Alpine.js at around ten kilobytes, Datastar for the server-sent-events approach, the HTMX team's own fixi at barely more than a kilobyte. One of them, declared plainly, is the author's own: htm/a, a study built to see how low the floor goes, server-side reactivity in about four kilobytes on the wire with a type-safe Rust core and no dependencies, running htma.run; not supported and not for sale, a proof that the floor is lower than the industry pretends. Wikipedia runs on MediaWiki in PHP, server-rendered, sixty million articles with no SPA; GOV.UK is mandated to progressive enhancement and ships HTML-first; Hacker News is server-side Common Lisp since 2007; Cloudflare replaced its nginx-with-Lua tier with the Rust service Pingora for around seventy per cent less CPU at a trillion requests a day; Netflix in 2017 removed client-side React from its logged-out page for about fifty per cent faster Time to Interactive. The author also built a small web server as a study, a Rust core with a Lua edge, and has run this site and a publisher's shop on it for months without incident. If the biggest names have chosen to do the work for less, the count is a choice, not a price the architecture forces. It persists for two non-technical reasons: the hiring market, where a junior trained on React, Webpack, Babel and ESLint is a known quantity and a senior asking for Hotwire is a re-hiring problem, and the deployment economy, where Vercel, Netlify and similar depend on the stack being heavy and their price scales with the bundle. Next Wednesday: the boundary that was never drawn, the security cost the architecture cannot fix." },
    { date = "Mon, 15 Jun 2026 00:00:00 GMT", title = "Definition of Unix", loc = "/blog/definition-of-unix", desc = "Unix Universe, the second of three Mondays on what Unix is. Last Monday's piece mapped where Unix runs in 2026; this one asks what it takes to be called Unix at all. Unix is not a vibe, it is a registration. The trademark UNIX belongs to The Open Group, a standards consortium based in the United States and the United Kingdom, which has kept the mark since 1996, when it was formed from the merger of X/Open and the Open Software Foundation; X/Open had received the trademark from Novell in 1993, and Novell from AT&T's Unix System Laboratories. To use the word commercially a system must be certified against the Single UNIX Specification, whose current edition, Issue 8, aligns with POSIX.1-2024; products certify against UNIX 03 or the newer and stricter UNIX V7, pass conformance tests, pay the licence fee, and join a public register. Sort systems by how they come to the word and they fall into three relationships. First, inheritance: the BSD family (FreeBSD, OpenBSD, NetBSD, DragonFly) carries the actual AT&T-and-Berkeley line in its source, traceable commit by commit back to Bell Labs in the late 1960s, Unix the way a child is family, by blood, with no certificate, no fee and no renewal date, and most of the BSDs have never been certified and are none the poorer for it. Second, certification: the route a new product takes to use the word commercially, with macOS the cleanest case (UNIX 03 since 10.5 Leopard in 2007), alongside IBM AIX (UNIX V7, the only product at that stricter level), z/OS and HP-UX; most of these are descended as well, so certification is usually a commercial layer over an inheritance, and the certificate behaves like a subscription that lapses when unpaid, as Oracle Solaris, Huawei EulerOS (lapsed 2022) and Inspur K-UX show. Third, resemblance: the Unix-like systems, the Unixoids, independent creations that took the Unix design as inspiration and rewrote the substance from scratch, BeOS in its own idiom, Linux most famously (the kernel Linus Torvalds began in 1991 out of admiration for Unix, with the GNU userland Richard Stallman's project had been building since 1983), and QNX on a microkernel of its own design. And off to one side, keeping its distance, the trademark: UNIX is not a roof over the family but a certification mark, which survives in law only by staying narrow, because the moment it is let to mean any Unix-ish system it turns generic and dies the way aspirin and escalator died; The Open Group disapproves even of the phrase Unix-like, saw off a 2007 challenge to the mark's validity, and pressed a German university over its UNIK short form. When The Open Group certifies a system as UNIX it measures the interface and only the interface, the C library and system calls, the shell, and the roughly 174 standard utilities the Single UNIX Specification lays down; it is silent on whether the thing underneath is Unix at all. IBM z/OS is the cleanest proof: it is certified UNIX and it is not a Unix, its kernel the mainframe MVS line, a design from the 1960s with no Bell Labs or Berkeley in it, and the certified part is UNIX System Services, a POSIX environment layered on top of MVS. The certificate attests that a system speaks Unix, not that it is one. Among the Unixoids, QNX repays the closest look: the real-time operating system Quantum Software Systems began near Ottawa in 1982, neither certified UNIX nor part of the BSD line, whose io-pkt networking stack is built directly on NetBSD's, with Berkeley's code compiled into its address space, and which holds a formal POSIX PSE52 certificate of its own, running in more than 175 million vehicles; on the family tree QNX sits close to Linux, both built outside the lineage, but a half-step nearer the trunk for the Berkeley code inside it. POSIX, the Portable Operating System Interface (IEEE 1003), first published as IEEE 1003.1 in 1988 and named by Richard Stallman, is the technical text the Single UNIX Specification incorporates; it specifies what a program sees and is deliberately silent on what implements it. The line matters because a fact about the code outlasts a subscription to a brand: the BSDs are Unix by descent, certified by nobody, answerable to no renewal date, and the part of the claim that does not expire is the part you inherit. Next Monday: the origin, Bell Labs in 1969 and the trail forward." },
    { date = "Sun, 14 Jun 2026 00:00:00 GMT", title = "The Single Tree", loc = "/blog/the-single-tree", desc = "IT Philosophy, the second of three on European software sovereignty. Three properties travel under the single banner of open source and are not the same: permission (may I read, modify, fork this, answered by the licence), forkability (can I hold a local tree at a cost I can bear, answered by the architecture), and jurisdiction (who governs the upstream and under whose law, answered by the institution). Most sovereignty programmes answer the first, mistake it for the third, and wonder two budget cycles later why the lever still reaches them. Linux is a kernel; what boots is a distribution assembled from kernel plus GNU coreutils, glibc, an init system, a package manager and several hundred independently-governed projects integrated by a maintainer. FreeBSD is a single project maintaining kernel, C library, userland, documentation, toolchain and release engineering in one source tree, released as one snapshot by one team. The technical phrase is base system: base meaning what is shipped together, system meaning integrated whole. Only permissive licensing truly lets go: fork FreeBSD and you import the code and nothing else; fork a GPL tree and the licence conditions travel with every line into your new system and remain there in perpetuity, because the kernel is GPLv2 and the GPL was designed precisely not to let go. The Linux Foundation 2024/2025 Annual Report states that 84,3 percent of kernel commits came from developers paid by their employers across more than 1.780 organisations; the kernel travels where the salaries point. In October 2024 the MAINTAINERS file was edited to remove approximately eleven entries under compliance requirements; Linus Torvalds confirmed the change and declined to reverse it; the Linux Foundation is registered in the United States as a 501(c)(6) and bound by US legal reach. Forking the source does not fork the governance. On 13 June 2026 the US Commerce Department directed Anthropic to suspend access to its two most capable models for all foreign nationals, three days after launch; the company complied and withdrew them from every customer, a commercial product serving hundreds of millions. Proprietary, paid, contracted, the opposite of open source, and it made no difference: the paying customer had no more leverage against the lever than the unpaid kernel contributor did. The lever is orthogonal to the licence. The only complete answer is to become the institution and govern the tree under your own law, which the permissive FreeBSD licensing model allows and the GPL variations that Linux is built from do not, since the GPL remains an unrepealable co-governor of any fork. Schleswig-Holstein is moving thirty thousand workstations off Microsoft onto Linux, LibreOffice and Nextcloud; France ordered ministries onto European-only stacks; both are real improvements and both are migrations onto GPL-family software described as sovereignty, which answers the permission question and leaves the institutional question where it was. The hardware layer is next Sunday." },
    { date = "Fri, 12 Jun 2026 00:00:00 GMT", title = "Nine Years in the Page Cache", loc = "/blog/nine-years-in-the-page-cache", desc = "Security Review, Friday 12 June 2026. On 29 April 2026 a researcher at Theori disclosed CVE-2026-31431, named Copy Fail: a Linux kernel flaw that lets an unprivileged local user become root. The full exploit, written in standard Python, fits in roughly 732 bytes. It does not race. It does not crash. It runs on Ubuntu 24.04, Amazon Linux 2023, Red Hat Enterprise Linux 10.1, SUSE 16, Debian, Fedora, Arch and any distribution shipping a kernel from the last nine years. CVSS v3.1 score 7.8 (High); the kernel security team was notified on 23 March 2026, the mainline patch landed on 1 April, the CVE was assigned 22 April, Theori disclosed publicly on 29 April. Eight days from report to patch. This is not the story of a single bug; it is three correct decisions, three different teams, fifteen years apart, that happened to meet in the page cache. The component is the authencesn template inside the Linux kernel crypto subsystem, exposed to userspace through the algif_aead module of the AF_ALG socket interface (in the tree since 2010). The exploit opens an AF_ALG socket, splices a file the user can read into the socket as the input buffer, and asks the kernel to perform an AEAD operation. Since 2015 AF_ALG has supported AEAD splicing, which holds direct references to the kernel's cached pages rather than copying their contents. In 2017 a performance commit (changeset 72548b093ee3) introduced an in-place optimisation: input and output reuse the same scatterlist. Inside authencesn (present since 2011 to support IPsec Extended Sequence Numbers), a four-byte scratch write lands inside a kmap_local_page mapping of the spliced file's page-cache page. The attacker chooses the file, chooses (through splice offset, splice length and assoclen) which four bytes get written, and chooses the value to write through bytes four to seven of the AAD. The result is a deterministic four-byte primitive against the in-memory copy of any file the user can read. The classical target is /usr/bin/su: the on-disk binary is unchanged, the page-cache copy that gets executed is corrupted, file-integrity tooling (Tripwire, AIDE, the host-based integrity layer of every modern EDR) compares disk hashes and sees nothing. Because the page cache is shared between containers and the host, a process inside a container with the right local privileges can corrupt the host's cached binaries; the container boundary does not stop this, it was never designed to. The Microsoft Security Response Center writeup is unusually direct about the cloud impact, and CERT-EU Advisory 2026-005 recommends disabling algif_aead until the patched kernel has reached every node. As of 12 June 2026, Arch, Fedora and Amazon Linux are on patched kernels, with Ubuntu, SUSE and Red Hat closing in; Debian's stable line is the slowest, which is consistent with Debian's general posture. The pattern: composite vulnerabilities do not have a single author; they emerge where responsibility lines cross. A kernel of 250,000 commits per year is maintained by hundreds of subsystem stewards; each is excellent within their own remit; the gaps between remits are where the seams sit. The Linux kernel community has been having a quiet conversation about AF_ALG: a 2025 LKML patch series titled Document the deprecation of AF_ALG proposes that new use cases should prefer userspace cryptography libraries. The BSD angle: FreeBSD exposes kernel cryptography through /dev/crypto (a device node, not a socket family); there is no AF_ALG-equivalent splice path; the OpenCrypto framework, descended from OpenBSD's OCF, was built in a different idiom. Capsicum (FreeBSD 9, 2012) lets processes relinquish access to global namespaces and operate only on file descriptors with explicitly granted capabilities; in active use by tcpdump, dhclient, auditdistd, kdump, ctld, iscsid. Containerisation on FreeBSD is a kernel-native primitive (jails plus VNET), not a daemon-mediated arrangement of namespaces. The same composite primitive does not, as far as one can see, have an equivalent path on FreeBSD. The recommendation is not patch and move on; it is check the seams. Wherever responsibility crosses team boundaries in the stack you maintain, fifteen years from now will be 2041. A kernel patch you accept this afternoon may, in 2041, sit alongside two other patches accepted by two other teams in two other years. The most one can do is make the seams as narrow as the architecture will tolerate, and keep an eye on which interfaces are quietly being deprecated by their own maintainers. One rather hopes the next nine years are a little duller in this regard than the last." },
    { date = "Wed, 10 Jun 2026 00:00:00 GMT", title = "The Unauditable Ones", loc = "/blog/the-unauditable-ones", desc = "Lean Software, the first of eighteen Wednesdays on how we got here. Open a fresh terminal. Pick the most common starting point for a modern web project, the one a bootcamp will tell you to take this week: npm create vite@latest my-app, template react-ts. Three minutes later, npm install settles. The shell returns. The project has not yet run. What is on disk: roughly 250 to 400 megabytes for the leaner choice (Vite plus React plus TypeScript), a typical Next.js install reaches 700 megabytes to a full gigabyte (the majority devDependencies), 100,000 to 220,000 files, 30 to 50 packages in package.json, 1,200 to 1,800 packages actually pulled in (the transitive closure), a maintainer count in the hundreds often four-figure. You have not written a line. Four things broke at the same time. One: the count was never justified. None of these volumes is required by what the project actually does. HTMX delivers reactivity in fourteen kilobytes minified, around five gzipped. MediaWiki runs sixty million Wikipedia articles on a server-rendered PHP stack with no SPA. GOV.UK is mandated to progressive enhancement and ships HTML-first. Hacker News is server-rendered Common Lisp. Hotwire gives full reactivity over the wire. Cloudflare replaced the standard nginx plus Lua web tier with a Rust service, Pingora, and runs around seventy per cent less CPU at one trillion requests per day. The 700 megabytes are a choice, not a requirement. Two: the boundary was never drawn. node_modules has no responsibility line; the line is absent because the architecture never drew one. There is no boundary between your application code and the 1,500 packages it pulls in; they run with the same permissions; the post-install script of any one of them can modify the others; the latest tag can shift retroactively, as the axios maintainer found on the morning of 31 March 2026. libc has a line: base source tree, named engineers, public roadmap, regular cadence, reproducible builds, signed artifacts. You know where libc lives, who is accountable, and how it arrived on disk; node_modules has none of these. Three: the workaround became architecture. Node.js arrived in 2009 with a single-threaded event loop; multi-core hardware required multi-container deployment because the runtime could not use the cores; the fix was more containers and an orchestrator to schedule them. Two decades later the container is the unit of thought, not the deployment artefact: a minimal Node.js image is 150 megabytes, the convenient default a full gigabyte, dockerd at 183 containers has been documented above five gigabytes of memory. The container architecture is a workaround for a language that cannot use the machine, dressed up as architecture. Amazon Prime Video returned its video monitoring to a monolith with a ninety per cent cost reduction; Segment consolidated 140 services into one; Istio merged its control plane back into a single binary. The reversal is happening. Four: the layers hide what they should bound. The ORM hides the SQL. The cache hides the ORM. The service mesh hides the services. The operator hides the YAML, which hides the kubelet, which hides the container, which hides the process. Each layer was, in its origin, an idea about containing complexity. Somewhere between Dijkstra's 1968 THE Operating System paper and the modern stack the verb shifted: containing became postponing. Lehman's second law of software evolution (1974) said it plainly: complexity rises unless explicit work is done to reduce it. The reduction is the work nobody is funded to do. These are four diagnoses; they share a system; none of them on its own is the whole problem. The next four Wednesdays take the axes one at a time (count, boundary, workaround, layers). Three pillars across the rest of the summer and into the autumn: npm in detail (15 July to 12 August), Docker in detail (19 August to 16 September), Teams and the labour market (23 to 30 September). The closing Wednesday on 7 October asks what could still be. The 700 megabytes are part of the problem; so is the rest of what follows. Four things broke at once, each defensible at the time it was introduced, each compounded by the next, each kept in place by an industry that has no interest in reducing it. The result is a system that is, on its own terms, unauditable: large where it could be small, ungoverned where it could be bounded, oddly shaped where it could fit the machine, layered where it could be plain. Next Wednesday: the count, and why none of it was justified." },
    { date = "Mon, 08 Jun 2026 00:00:00 GMT", title = "Where Unix Runs Today", loc = "/blog/where-unix-runs-today", desc = "Unix Universe, the first of three Mondays on what Unix is. Open the laptop in front of you. If it is a Mac, you are on certified Unix; every version of macOS from 10.5 Leopard (2007) through 15 Sequoia (2024) has been certified by The Open Group as conforming to UNIX 03. The phone in the pocket is Darwin underneath, the same family. The Netflix stream you watched on Friday came off an Open Connect appliance running FreeBSD; the TLS offloading that lets a single box push around 375 gigabits per second on roughly half its CPU is a FreeBSD-13 feature written by Netflix engineer Drew Gallatin in collaboration with Chelsio; the Open Connect network pushes over 100 terabits per second at peak across thousands of appliances; a substantial share of evening internet, globally, is FreeBSD. Both PlayStation 4 and PlayStation 5 boot a Sony-customised FreeBSD: PS4's Orbis OS is derived from FreeBSD 9, PS5's Orbis 2.0 from FreeBSD 11; over 200 million units have shipped. Junos OS has been FreeBSD-based since its first release in July 1998 and runs a substantial part of the internet's backbone routing equipment; classical Junos tracks the FreeBSD versions (R15.1 on FreeBSD 10, R21.1 on FreeBSD 12, R24.2 on FreeBSD 14). Junos OS Evolved (from R18.3, 2018) is a newer variant built on a Linux kernel rather than FreeBSD; both lines exist in parallel. The world's commercial Unix systems are not all in retirement homes: IBM AIX is actively developed and AIX 7 is the only operating system in the world certified at UNIX V7 (SUSv4) level; Oracle Solaris is in sustaining support, no major new features, still in telecom carrier infrastructure and long-cycle replicated databases; HP-UX is genuinely fading, tied to discontinued Itanium hardware, runs where it runs; z/OS on IBM mainframes is certified Unix and runs a substantial part of the world's banking transaction processing. For a long stretch the WhatsApp backend ran on FreeBSD with Erlang on top; after the Meta acquisition the stack changed, but the point Rick Reed and Jan Koum made publicly at the time survives: FreeBSD's coherence and its network stack let a small team carry a very large user base. Linux is not on this list, not because Linux is unimportant (it carries an enormous share of the world's cloud servers, embedded devices and Android phones) but because Linux is not Unix; it is Unix-like; Linus Torvalds wrote the Linux kernel from scratch in 1991 with no inherited Unix or BSD code; the standard userland comes from GNU not from AT&T or Berkeley; Linux has never been certified by The Open Group and is not on the UNIX trademark register. It is a separate family. It looks Unix-shaped because that was the design intent, but the genealogy is its own. Unix is not a historical curiosity. It is the operating-system family under your phone, under your laptop, behind your Friday-evening stream, inside the router that carries your call, in the back office of the bank that holds your salary, and inside the console your nephew is shouting at in the next room. You have been holding Unix all morning. Next Monday: the standards question. What does it actually take to be allowed to say Unix, and who decides?" },
    { date = "Sun, 07 Jun 2026 00:00:00 GMT", title = "Open Is Not Owned", loc = "/blog/open-is-not-owned", desc = "IT Philosophy, the first of three on European software sovereignty. A great deal of procurement language at the moment treats open source as a sovereignty answer; the reasoning is that proprietary cloud providers are foreign-jurisdiction firms, open source is by contrast open, therefore open source is sovereign. The conclusion is louder than the premises warrant. Open and owned are not the same word; they overlap in places, they diverge in others, and where they diverge tends to be precisely where procurement assumes they do not. The question is being asked across multiple jurisdictions: France's Interministerial Digital Directorate (DINUM) announced in April 2026 a migration of its own workstations from Windows to Linux with a directive to all ministries to formalise plans for eliminating extra-European dependencies by autumn; Huawei launched its HarmonyOS PC line in May 2025 after the company's Windows licence was withdrawn under US sanctions; India produces BharOS through IIT Madras and government sponsorship; China's procurement directives favour domestic ISA work at the chip layer. A licence is not a deed of ownership, it is a statement of conditions. The licence landscape needs three shelves rather than two. Permissive licences (BSD 2-Clause, BSD 3-Clause, MIT, Apache 2.0) let anyone build on the code, fork it, ship it, sell it and combine it with other code under any licence at all; original authors retain attribution. Copyleft licences (GPLv2, GPLv3, LGPL) let anyone receive and modify the code but require that any distribution of the modified version arrives under the same licence. Network copyleft licences (AGPLv3) extend copyleft to the case where the modified version runs as a service rather than being distributed as a binary; Section 13 closes what is sometimes called the SaaS loophole of classical GPL. The Server Side Public Licence (SSPL), introduced by MongoDB in 2018 and adopted by Elastic in 2021, extends AGPL's network clause to require open-sourcing of the entire surrounding management stack; the Open Source Initiative declines to recognise SSPL as open source citing field-of-use discrimination, so SSPL is a fourth shelf that does not behave like the other three. The European Union Public Licence (EUPL-1.2) sits in the copyleft family and is OSI-approved; it exists in part because the EU wanted a Union-grounded licence with cross-Member-State legal certainty in twenty-three languages. GPL keeps the code open, it does not return it to the receiver: every downstream version remains under GPL, the original author's licensing choice propagates indefinitely, and a European entity that needs to take a piece of GPL code and integrate it with proprietary or commercially-sensitive surrounding code finds that GPL has decided the licensing of the surrounding code as well, because the licence absorbs. A useful demonstration is FreeBSD's compiler migration: FreeBSD 10.0 (January 2014) moved its base system from GCC to Clang; the technical case existed but was not decisive, the decisive factor was that GCC had moved to GPLv3 and a coherent permissive base could not host a copyleft compiler whose conditions would leak outwards. AGPL is the honest middle: if you modify this code and use it to serve users over a network the users have a right to your modifications; it does not require you to share user data, internal management software, or anything outside the modified program itself, which is exactly what tipped SSPL out of the OSI classification. The xz incident reminds us that open is not audited: in March 2024 a Microsoft engineer named Andres Freund was profiling SSH connections, noticed unusual CPU time inside liblzma, and discovered a backdoor (CVE-2024-3094, CVSS 10.0) inserted by a maintainer operating under the name Jia Tan after a multi-year social-engineering campaign that began in 2021; the backdoor was discovered by one person's curiosity, not by the audit infrastructure of the open-source ecosystem, because permissive licensing makes audit possible, it does not make audit happen. In October 2024 the Linux kernel project removed approximately eleven maintainers from a particular jurisdiction subject to expanded US sanctions; the change appeared on the kernel mailing list as compliance requirements, Linus Torvalds confirmed it shortly afterwards and declined to reverse it; the specific jurisdiction is not the point, the point is that the Linux Foundation is registered in the United States and US sanctions reach the operations of US-registered organisations, so whichever jurisdiction comes under expanded US legal pressure next has the same exposure to the same mechanism. The CLOUD Act (March 2018) permits US law enforcement to compel US-based service providers to hand over data regardless of where that data is stored; Schrems II (Court of Justice of the European Union, Case C-311/18, July 2020) held that US surveillance law under FISA Section 702 and Executive Order 12333 does not meet the proportionality standard required by EU law and invalidated the EU-US Privacy Shield. These create a strong reason for European public services to prefer software stacks they can host, modify and audit locally; the same reasoning runs in Beijing, New Delhi, Moscow, Brasilia, with the relevant counterpart jurisdiction differing in each case. A licence is a permission slip; sovereignty is the practice of using the permission, which consists of reproducible local build, audit and signing, and continuous re-receipt. A receiver who owns the licence but does not own the build infrastructure does not own the result; a receiver who owns the build infrastructure but runs it on someone else's silicon has only moved the question down a layer. This piece sets the question; the architectural layer is next Sunday, the silicon layer the Sunday after." },
    { date = "Sat, 06 Jun 2026 00:00:00 GMT", title = "A Change of Shape", loc = "/blog/a-change-of-shape", desc = "An editorial pivot post. After almost two hundred posts written under nine series labels (Technical Beauty, The Unix Way, By Design, In the Net, Not in the Brief, On Second Thought, Tales from the Bare Metal, Bytes of Art, The Invoice), the labels are coming off. None of the old bodies of work go away; the archive stands and the pieces remain readable, but no new pieces are being written under those mastheads. The series-brand format, after some hundreds of posts, becomes a procrustean bed: each post arrives pre-shaped by the masthead it is assigned to, by the conventions of its series, by the hook symbol that needs to be there because the hook symbol has always been there; the shape is doing some of the writing, and that is starting to flatten the work. The recurring readers who think for a living about systems do not write under series labels themselves; they write essays. A reader might fairly point out that this transition itself involves a fair amount of branding (new ressort names, new colour palette, a layout master, a typography discipline); there is no honest way to deny the observation, and less labels would be a more accurate description than less branding. What stays: the British editorial tone, the British humour, the dry technical precision, the FreeBSD anchor wherever it earns its place, the honest disclaimers that say where the argument ends, the LinkedIn first-comment link to the full piece on vivianvoss.net, the Sunday long-form discipline, the respect for readers across the BSD and Linux divide. Security gets its own fixed weekly slot: the interruptive Wire Fire sitrep, which fired on demand when a tier-one event crossed the threshold, has been retired in favour of a scheduled Friday column with the same brief at a calmer cadence. The new shape: four days, four ressorts, each day belonging to one set of questions. Monday is Unix Universe (FreeBSD engineering, BSD and Linux comparisons, the engineering tree that holds together as one coherent base system). Wednesday is Lean Software (less code, less framework, less bloat, the discipline of subtraction in the stack, the five-kilobyte question for a typical single-page application, the build step you did not need, the microservice for a two-person team, the polyfill that outlived the browser it was written for). Friday is Security Review (vulnerabilities and vendor moves in the territories engineers actually work in, BSD and Unix CVEs with real production reach, European vendor and governance shifts, supply-chain compromises; not an alarm, a briefing, on what to know before the weekend). Sunday is IT Philosophy (architecture as ethics, ownership versus accessibility, licence philosophy and European software sovereignty, AI provenance, Wabi-Sabi engineering, the single ressort where each piece carries its own limit on where the argument ends). Within each ressort, pieces will sometimes run as small bows of two or three over consecutive weeks with a one-of-three or two-of-three marker on the cover; they will sometimes run as a single solo essay; they will occasionally take a Sunday-long-form turn into a fuller essay on the blog. Tomorrow opens the first bow on Sunday: the first of three pieces on European software sovereignty, under the title Open Is Not Owned, asking whether the licence of a piece of software is the question of who actually owns it. The second piece walks through the single coherent base system that makes ownership actually possible in practice. The third names the layer of the stack that cannot be forked at all, regardless of licence. A small editorial week begins. Same writer, four angles, sharper form. The hooks come off; the work does not." },
    { date = "Fri, 05 Jun 2026 00:00:00 GMT", title = "The Terms You Did Not Sign", loc = "/blog/the-terms-you-did-not-sign", desc = "In the Net Episode 06. On 10 August 2023 HashiCorp announced that all future releases of Terraform, Vault, Consul, Nomad, Packer, Boundary, Waypoint and Vagrant would move from the Mozilla Public License v2.0 to the Business Source License v1.1; there was no consultation, the announcement was a press release. Forty-one days later, on 20 September 2023, the Linux Foundation accepted OpenTofu, a community fork of Terraform held under MPL 2.0, with founding sponsorship from Spacelift, Harness, Gruntwork, env0 and Scalr; by January 2024 OpenTofu 1.6 shipped as a drop-in replacement. On 24 April 2024 IBM announced its intent to acquire HashiCorp for $6.4 billion (approximately $35 per share in cash); the acquisition closed on 27 February 2025 after the U.K. Competition and Markets Authority granted clearance. The Terraform file in your repository, written before any of this, is on a different licence today than it was on the day you wrote it. HashiCorp made infrastructure boring, in the best sense: for nine years (Terraform 0.1 shipped July 2014) the source was MPL 2.0, a file-level copyleft permissive enough that a CI provider could host runs, a consultancy could automate it, a wrapper could extend it, all without negotiation; the de facto IaC standard had Open Source mechanics behind it. The Business Source License 1.1 is not Open Source by the OSI definition; it is source-available, in which you may read and use the source for purposes the licensor permits but cannot use for any purpose or redistribute modified versions. The BSL contains an Additional Use Grant in which the licensor names the things you may not do; HashiCorp's grant forbids production use that competes with HashiCorp's commercial offering (Terraform Cloud, Terraform Enterprise, Vault Enterprise, Consul Enterprise and adjacent services). What constitutes competition with is ambiguous on the face of the licence text, and the ambiguity is the design point. Three mechanics matter. Every binary built from official source after 10 August 2023 falls under BSL until exactly four years after that release, when the licence on that version (and only that version) converts to MPL 2.0; Terraform 1.5.7 remains MPL forever, 1.6.0 onwards is BSL for four years from each release date. Forking BSL code as Open Source is forbidden by the BSL itself; forking as proprietary or source-available is permitted; OpenTofu was forked from Terraform 1.5.7 precisely because it was the only legal fork-target. HashiCorp's APIs, SDKs, libraries and provider plugins remain MPL 2.0; the core binary changed, the surrounding ecosystem mostly did not. OpenTofu was forked very quickly: 25 August 2023 manifesto, 20 September 2023 accepted by the Linux Foundation, January 2024 OpenTofu 1.6 first stable release fully compatible with Terraform 1.5.x in module syntax, provider ecosystem and state file format; a terraform apply followed by a tofu apply on the same state file is a working migration path. OpenTofu crossed 20,000 GitHub stars within months. The community voted with its mirror. The Business Source License is reversible at the licensor's discretion only; HashiCorp or IBM could restore MPL 2.0 tomorrow, or extend the four-year period, or modify the Additional Use Grant, or replace BSL altogether. This is Lock-in by Retroactive Adoption: the hooks were not laid when you adopted the tool, they were retrofitted onto the version-stream of the tool you had already adopted, and the retrofit happened because a press release said so, not because you renegotiated. The price: Terraform Cloud SaaS prices per applied resource per concurrent run per workspace; Terraform Enterprise starts at five-figure annual commitments; Vault Enterprise prices per client per month; large estates reach six and seven figures yearly. The pricing was the same before the BSL change as after; the licence change redefined the legal terms on which the free version was available, pushing organisations built on the free version toward either the commercial version or a migration; the licence is the leverage, the pricing is the price of staying. Escape routes: For Terraform, OpenTofu (Linux Foundation, MPL 2.0), drop-in for the terraform binary, state files forward-compatible, hcl identical, provider plugins reusable. For Vault, OpenBao (Linux Foundation, MPL 2.0), forked at Vault 1.14.x in late 2023, GA December 2024. For Consul, pinned-version OSS or migration to Istio/Linkerd (service mesh) or etcd (KV-store). Beyond the BSL stack: Pulumi (Apache 2.0), IaC in Python, Go, TypeScript, C-sharp, a real port rather than a swap; Crossplane (Apache 2.0), Kubernetes-native composition with cloud resources as Custom Resources. Practical hygiene: avoid Terraform Cloud private registries and sensitive-variable storage, pin provider versions explicitly, keep CI runners self-hosted, maintain state file backups. The sixth distinct lock-in genus: Adobe took your file format, LinkedIn took your reach, AWS took your identity and egress, VMware took your perpetual licence in an acquisition you were not party to, Oracle took your Java users and billed your entire workforce, HashiCorp now IBM took the licence on the source of the tool you had already adopted, four years deep into your platform, and changed it under your feet. You wrote infrastructure as code so the next engineer could read it. You did not promise the next licence-holder would let them." },
    { date = "Thu, 04 Jun 2026 00:00:00 GMT", title = "Unix, Everything Is a File", loc = "/blog/unix-everything-is-a-file", desc = "By Design Episode 07. In the summer of 1969 Ken Thompson had three weeks of uninterrupted time at Bell Labs while his family was visiting California, an empty PDP-7 with four kilobytes of memory and the lingering question of what a smaller, cleaner operating system might look like. By the end of those three weeks he had written the first version of what became Unix; with Dennis Ritchie and Rudd Canaday the Bell Labs group built a hierarchical filesystem, processes, pipes, a command interpreter, and one architectural idea that has carried half a century without much fading: the file as the universal interface. A device, a pipe, a socket, a process listing, all opened, read, written and closed through the same system calls. The complaint sockets are not files and GPUs are not files and hardware state does not fit a read() is older than the design and not unfounded; ioctl exists precisely because some operations refuse to pretend they are bytes. The Unix answer is to extend the file when possible, accept the ioctl when not, and keep the path-and-handle vocabulary as the default. Devices live in /dev/ (/dev/null, /dev/random, /dev/zero), pipes are anonymous file descriptors created by pipe(2), sockets are file descriptors after socket() (added in 4.2BSD, 1983), processes are inspectable as /proc entries. Ritchie and Thompson's 1974 ACM paper, The UNIX Time-Sharing System (CACM volume 17 number 7), codified what had been on the PDP-7 since 1969. Plan 9 from Bell Labs (Pike, Thompson, Presotto, Winterbottom, first edition 1992) pushed the idea to its logical end: the window system is a file system, the keyboard is a file system, remote machines are mounted as file systems through the 9P protocol, even computation can be a file system. Dennis Ritchie said of Plan 9 that Unix had the right idea but did not follow through; Plan 9 followed through. The trade-off is honest: not every operation fits a sequence of bytes. A terminal driver has a stty configuration no read() will reveal; a network interface has an IP address you do not write into a file the way you write into one; GPU drivers are the most striking modern case, with command queues, memory allocators and shader compiler interfaces. DRM (Direct Rendering Manager) is the practical compromise: the GPU is a file in /dev/, opened like everything else, and then almost all the work happens through ioctl. The trade is honest: the file model is not free, it is cheap because the alternatives are expensive. Fifty-six years on, the file is still the unit. On FreeBSD the discipline is intact: devfs (in-base since FreeBSD 5.0, 2003) presents the kernel's device tree as a regular filesystem, GELI exposes encrypted volumes as /dev/<name>.eli, ZFS volumes appear under /dev/zvol/<pool>/<name>, bhyve presents virtual machine handles under /dev/vmm/. Plan 9 is the pure version, still maintained at 9front.org. Linux started the same way and has, in some corners, drifted: D-Bus (2002) carries the message bus earlier Unix work would have built as files and sockets; systemd (2010) builds its own interfaces around cgroups, sockets, the journal and dbus services; Netlink is the alternative kernel channel for routing, audit and firewall; eBPF is a programmable layer that runs verified bytecode rather than a path that names a piece of state. None are wrong; the cumulative effect is that the Linux of 2026 has, in several important corners, become a system in which the file is one of several interfaces rather than the interface. Ritchie's verdict on Plan 9 was that Unix had the right idea but did not follow through; the same sentence, read against 2026 Linux, has rotated by 180 degrees; the FreeBSD line is closer to the original commitment, deliberately so. One interface, infinite implementations. The protocol the kernel offers (open, read, write, close, ioctl as escape) and the abstraction the shell composes (the |, the <, the >, the 2>&1) are the same protocol viewed from different ends. A Unix one-liner reads almost like a sentence because every noun in it is a file." },
    { date = "Wed, 03 Jun 2026 00:00:00 GMT", title = "The Eighth Server", loc = "/blog/the-eighth-server", desc = "Tales from the Bare Metal Episode 06. At 09:30 on 1 August 2012 the New York Stock Exchange opened the Retail Liquidity Program; by 10:15 Knight Capital Group, one of the largest market makers on American equities, had ceased to function as a going concern. The forty-five minutes between cost the firm roughly $440 million in realised pre-tax loss, required around $400 million of emergency capital from Jefferies within days, drew a $12 million SEC fine for violations of the Market Access Rule, and led to acquisition by Getco before the year was out. The proximate cause was one server out of eight, running code from 2003 that, in a source-control sense, had never gone away. Knight's SMARS, the Smart Market Access Routing System, ran on eight production servers; the release prepared for the RLP launch reached seven of them, on the eighth the deployment did not complete, and nobody knew. When the markets opened, retail orders bearing the new RLP flag were routed correctly by the seven; the eighth interpreted the same flag through code paths last meaningful in 2003. The defective behaviour came from a module called Power Peg, written in 2003 as a parent-order management test routine, disabled after 2005 by a flag and never deleted; the disabling was operational, not structural. In 2012 the same flag bit was repurposed to signal RLP eligibility. On the seven up-to-date servers the bit meant RLP. On the eighth, in code from 2003, the bit still meant start Power Peg. Each RLP-eligible order woke a nine-year-old corpse. Power Peg had no production-grade concept of order filled; it bought at the ask and sold at the bid until told to stop, and nobody had told it to stop in nine years. Around four million orders, around seven billion dollars of unintended positions, hundreds of stocks visibly moved, and a firm absorbed. Three quiet drifts compounded, none foolish at the time. The first was the source tree: in 2005 the team that decided Power Peg was unfit gated it with a flag rather than deleting it; the gating worked perfectly, every day, for seven years; the engineers who made that decision were no longer present in 2012, and the link between the flag, the gated module and the bit position existed in nobody's head. The second was the deployment script: it treated deployment as a file-copy operation, reporting success when files had landed and SMARS had restarted, without interrogating each host for a build identifier or requiring a healthcheck that only the new code could pass. The third was the release note: it recorded that the cumulative-quantity-flag bit was now being used to signal RLP eligibility, but did not record that the same bit had once been the activation signal for an ancient module still compiled into the running binary. All three were ordinary; every team does at least one, most teams do all three; Knight's bad luck was to do all three on the morning a stock exchange opened a new programme. Two architectural disciplines would have prevented it. Delete dead code, do not gate it: a flag that disables a module is a switch an unrelated change can later flip; a deleted module is gone from the binary and the running process. Verify after deploy on the property of the deployed code itself: the end of a deployment is not the files copied successfully, it is every target host reports the new build's identity; a script that hits /version on each host after restart, compares the returned hash to the expected hash, and fails loudly if any host disagrees, is half a page of shell that catches the specific class of failure that ended Knight Capital. In a FreeBSD shop this is rc.d managing the SMARS-equivalent plus a deploy script in plain shell that loops over the host list, hits /version on each, and refuses to declare success until every host returns the expected build. The pattern wears the local clothes everywhere it travels. Kubernetes: a rolling update on a Deployment where one node has the image cached under the same tag from a previous build; with imagePullPolicy: IfNotPresent the kubelet uses the cached image, the readiness probe passes from either version, and the Deployment reports rolled out with one pod silently still on the old code. Feature-flag libraries (LaunchDarkly, ConfigCat, Unleash, Flagsmith): a flag whose semantic meaning has shifted between releases; the old code path is still in the binary, gated by the same flag, waiting for somebody to wake it. Cloud auto-scaling: an EC2 launch template that points at an outdated AMI ID; newly scaled-out instances run the old binary while the freshly-deployed ones run the new. Helm and Kustomize: a Deployment manifest pins version 2.4.0, but one cluster node's local image cache resolves the tag to an older 2.3.7. CI/CD job matrices: a deployment job that reports success when N of N return zero exit codes without verifying any target's running version. The shape is identical in each: a release that completes on N minus one out of N targets, a verification step that asks did the deploy succeed rather than is the new version running everywhere, and a piece of latent surface area lying in wait on the unverified one. The single sentence worth carrying out is the question that ends it: when our deployment reports success this afternoon, on what property of the deployed code did it confirm that? A deploy that succeeds on seven of eight is one that failed quietly on one. Production does not give partial credit; the market gives none at all." },
    { date = "Tue, 02 Jun 2026 00:00:00 GMT", title = "patch", loc = "/blog/patch", desc = "Technical Beauty Episode 38. A maintainer sends you a fix; not a branch on a server, not a pull request awaiting a token, not an invitation to fetch a remote you have not heard of, but a text file with plus signs and minus signs and a few lines of plain context around them, attached to an email or pasted into an issue. You drop it onto your tree, type one command, and your code is current; no credentials, no network, no infrastructure. The format that taught the world to ship a change in a dozen lines arrived in 1985, written by a man who would invent Perl two years later. A patch is a recipe, not a snapshot: it does not contain the new file, it contains the change that turns the old file into the new one, which is the reason a fix to a million-line codebase can travel as twenty lines of email. The vocabulary is small: a header naming source and destination paths, hunks with their own little headers (the line ranges in the old and new versions, @@ -42,7 +42,9 @@), context lines space-prefixed, deletions minus-prefixed, additions plus-prefixed; the context allows the apply tool to find the right place in the file even when the surrounding code has drifted by a few lines. The whole standard fits on a page. The daily idiom is two commands: diff -u original modified > change.patch to make one, patch -p1 < change.patch to apply it; -u for the unified format (the one every modern tool produces), -p1 to strip one leading directory from the recorded paths, so a/src/main.c applies to src/main.c in your tree. Further flags: patch -R to reverse, patch --dry-run to check without writing, patch -i for explicit input. When a hunk does not fit cleanly the tool tries line-fuzz, a small tolerance for context drift; if even that fails, it writes the rejected hunk to a .rej file beside the target, plainly, in the original format. The tool is honest about its limits and tells you exactly what it could not do; beauty, here, includes telling the truth about failure. FreeBSD ships patch in base at /usr/bin/patch, BSD-licensed, descended directly from Larry Wall's original source line; OpenBSD, NetBSD and macOS carry the same lineage. GNU patch, part of the GNU project, is a separate fork from the same root, GPL-licensed; the on-disk format both tools read and write is the same, so a patch produced by git diff on one machine applies on any machine with either implementation. That interoperability after forty years is not an accident; it is what one gets when the format is small enough to specify completely and honestly. Larry Wall posted patch 1.3 to the mod.sources newsgroup on 8 May 1985, from his desk at NASA's Jet Propulsion Laboratory in Pasadena; he had already written rn the year before, and Perl was still two years away. Wall borrowed the diff output that the BSD diff(1) tool already produced (in the older context-diff format) and turned it from a thing humans read into a thing programs apply; that move, treating diff output as a machine-readable changeset rather than a human report, is the conceptual reduction the rest of the story rests on. In August 1990, Wayne Davison posted unidiff to comp.sources.misc, volume 14: a new format that interleaved deletions and insertions into a single block, sharing the context between them, and saved roughly a quarter of the bytes. Richard Stallman folded unidiff support into GNU diff 1.15 in January 1991; patch learned to read it shortly after; the unified format has been the lingua franca ever since (git produces it, GitHub shows it, every code-review tool speaks it). A bug found in 2020 by Warner Losh while restoring 2.11BSD traced a thirty-five-year-old corner case in the original parsing and was triaged identically against both lines. Forty-one years on, BSD patch in FreeBSD base and GNU patch are still interoperable, and a 1986 patch -p1 still works on a 2026 FreeBSD installation. A format becomes universal when it is small enough to be a sentence. Wall's was." },
    { date = "Mon, 01 Jun 2026 00:00:00 GMT", title = "procstat vs lsof", loc = "/blog/procstat-vs-lsof", desc = "The Unix Way Episode 19. Cannot remove text file busy, Address already in use, Mount point is busy, and the silent contradiction in which df reports a filesystem at ninety per cent while du can only account for half the bytes: four different refusals, one shared question, which process is holding it open? FreeBSD and Linux both answer it, in their own shapes. The modern FreeBSD tool is procstat(1), introduced by Robert N M Watson and shipped with FreeBSD 9.0 in 2012, built on libprocstat(3), a stable C library every program needing process state can link against directly, so the FreeBSD ecosystem (top, gstat, debugger front-ends, monitoring tools) draws from one common source rather than parsing text or scraping /proc. procstat is the per-process introspection front-end: -f file-descriptor view, -t threads with states, -v virtual-memory map, -k kernel stack, -s security credentials; different flag, same tool, same library underneath. Its classical sibling is fstat(1), in the base system since 4.3BSD-Tahoe in 1988, the system-wide ledger of every open file by every process, narrowed by -p pid, -u user, an exact path, or -f mountpoint. The case that most often justifies either tool in production is the deleted-but-held file: a long-running daemon opens a logfile and something unlinks it while the daemon still holds it open, so the directory entry is gone (du cannot see the bytes) but the inode and its blocks remain allocated until the last fd is closed (df still counts them). fstat shows such a file with a dash in the inode column; fstat -p pid piped to awk '$5==\"-\"' names it. The cure is to close the fd: a graceful restart, a SIGHUP, or a logrotate hook. On Linux the same question is answered by lsof(8), written by Vic Abell at Purdue University and first released to comp.sources.unix in 1991; two years earlier, in 1989, he had ported BSD's fstat and ofiles to DYNIX, SunOS and ULTRIX, and lsof is in direct line of descent, a generalisation of the BSD idea. The universal hammer: regular files, directories, sockets (TCP, UDP, raw, Unix-domain), pipes, anonymous inodes, character and block devices, and the synthetic entries the kernel exposes through /proc. Basics: lsof -p pid, lsof +D path (recursive, slow), lsof -i :port, lsof -u user, lsof +L1 (link count below one: deleted but held), lsof -n -P (skip DNS and service-name lookups). lsof +L1 is the Linux answer to the FreeBSD awk-dollar-five-equals-dash pattern, the right reach the first time when df and du disagree. Almost everything lsof reports is derived from /proc: each running process has /proc/pid/ containing fd/, a directory of symbolic links to the actual files, sockets or pipes; the kernel-maintained net/ files describe socket state. lsof is, in a real sense, a structured tour of /proc presented as one consistent output. Two answers to the same question, two different shapes. FreeBSD splits the work between procstat (focused per-process), fstat (broad system view since 1988), and libprocstat (the C library any tool can link against); each piece does one thing and the pieces compose, the next tool does not need to parse text. Linux folds the same work into one large lovingly maintained binary; lsof understands every kind of open file and every kind of socket, reads from /proc and kernel symbol tables and netlink, and presents the union as one consistent output. There is no liblsof because lsof is itself the interface; its sustained existence as one program is what makes its breadth possible. Neither shape is wrong; the Linux model trades modularity at the C-library layer for completeness at the command-line layer, the FreeBSD model trades single-binary breadth for a layered design in which every program that needs process state asks the same library, in the same way, and the user-facing tools are thin clients of that library. The first is delightful when you have one weird question and a hurry to answer it; the second is delightful when you are writing the next tool, or when you want top and your monitoring agent and your shell prompt all reading the same kernel reality. Both ship with the OS. Neither asks you to install a runtime. Neither wants JSON. When a system refuses to do what you asked, ask it precisely what is in the way; the kernel will tell you, plainly, on either platform. The Unix way prefers parts that compose; lsof prefers parts that arrive together. Learn the flags before the page goes off." },
    { date = "Sun, 31 May 2026 00:00:00 GMT", title = "Why We Restart to Fix It", loc = "/blog/why-we-restart-to-fix-it", desc = "On Second Thought Episode 10. The pager goes off, memory on the auth service is climbing, the on-call engineer SSHs in, observes nothing in particular, runs kubectl delete pod, the pod returns and memory is fresh, the alert clears and nobody asks what was wrong. The runbook for half the world's incidents has three steps and only the last one matters. The reflex has two parents and we kept only one. The first is the consumer-electronics tradition: a device with no language to be asked has only its power switch (a Sky+ box, a wireless router, a Windows laptop), honest about its limits and reasonable for the hardware of its time. The second was built deliberately to replace it. In 1986 at Ericsson's Computer Science Laboratory in Stockholm, Joe Armstrong, Robert Virding and Mike Williams began Erlang for telephone exchanges that could not go down; the AXD301 ATM switch runs on roughly two million lines of Erlang and is the system most often cited for nine-nines reliability (the figure is contested, the architecture is not). Armstrong's principle on the surface looked the same: terminate the bad process; he called it let it crash, and the phrase has done more damage to the idea than any critic could. Read as a slogan it sounds like the Sky+ box; read as architecture it is the opposite. Three properties make it architecture: processes are isolated (an Erlang process has its own heap and message queue and shares nothing mutable with any other, so a crash takes itself with it and nothing else); every worker has a supervisor (a specific process defined in OTP, the standard Erlang library, to which crashes are delivered as messages); the supervisor decides according to a written strategy with names (one-for-one restarts only the crashed worker, one-for-all restarts all siblings, rest-for-one restarts the crashed worker and any later in the dependency order) and an escalation limit (when the maximum restart frequency is exceeded the supervisor itself crashes and the failure escalates one level up the tree). A failure is data, handled by a rule written years before the outage. Let it crash, properly read, is the IT Crowd if Roy were a written contract. The restart is the same gesture, the contract underneath is wholly different. So the restart is the diagnosis: pod returns, alert clears, day shipped; a memory leak, file-descriptor exhaustion, lock contention and a downstream throttled queue each leave the same heartbeat-recovery signature on a dashboard and need a different fix, and the restart erases the question that distinguishes them. The structural cost: Kubernetes liveness and readiness probes are, honestly read, a contract that the orchestrator rotates the symptoms while the cause goes unexamined; there is no concept in the standard flow of capturing the dying process's state, of preserving the crash for inspection, of asking why before the next pod is scheduled. Self-healing is accurate in the sense that a person who takes paracetamol every four hours has a self-healing headache. The institutional cost: a team that restarts to fix gets very good at restarting and never gets good at diagnosing; the post-incident review adds a command to the runbook and the collective intuition shifts from what is this system actually doing to what sequence of recovery steps clears the current alert. There is software in operation that does not work this way. WhatsApp serves over a billion users with around fifty engineers, on Erlang, on the Stockholm supervisor architecture; the engineers spend their day writing the rules under which the boxes manage themselves. In the unixoid tradition the FreeBSD base provides the operator's half: init and rc.d use explicit start, explicit dependency and explicit recovery; when a service misbehaves the operator has dtrace to follow what the kernel and user-space code are actually doing, ktrace to record system calls for later inspection, procstat and fstat to read what a process is holding, post-mortem core dumps that survive the crash, and a kernel willing to say what process held what lock at what time. The reboot is available, rarely the first reach, because the system is willing to speak and the operator has been trained to listen. The honest question is not whether to keep the restart; the runbooks have it for a reason. The question is the one we did not write down: was the restart the answer, or the moment the question got dropped? A restart, on second thought, is not a tool. It is a measurement. It tells you, with some precision, how much of the cause you decided you could afford to leave unknown." },
    { date = "Sat, 30 May 2026 00:00:00 GMT", title = "The OS That Brought Its Own AI", loc = "/blog/the-os-that-brought-its-own-ai", desc = "Not in the Brief Episode 05. Sometime between Android 14 and 16, Google Assistant retired and Gemini moved into the OS-level assistant slot on every eligible device, the same long-press, the same Hey Google. Pixel 10 (announced 20 August 2025, shipping from 28 August 2025) shipped with Gemini already there; on the rest of the eligible Android estate (Android 10 or later, 2 GB RAM and up) Gemini arrived as a system update during 2025, in some cases as a notification offering to upgrade the existing assistant, framed in that wording as the outdated version of itself; devices below the threshold keep classic Google Assistant by default, not by choice. The standalone Google Assistant retires on or around 31 March 2026 with the full sunset announced in December 2025, after which the only choices Android presents in the digital-assistant slot are Gemini or None; the third option that existed for nearly a decade is going away on a published schedule. A digital assistant on Android is a role, not an application: the OS exposes a hook (the assistant role), exactly one application at a time is the holder, and the long-press of the home button, the wake word and the assistant intent from any third-party app all route to it; until 2024 the holder was Google Assistant, now it is Gemini, the same downstream apps and a different programme at the other end. On Pixel-class hardware Gemini Nano runs on-device for a slice of the work and powers Magic Compose in Google Messages (style variants Formal, Excited, Chill, no internet required), Call Notes (Pixel-exclusive written summaries of phone calls), Pixel Recorder summaries (three-bullet for recordings longer than thirty minutes) and Scam Detection (real-time analysis of fraud-script patterns); for anything heavier the call leaves the phone for a larger model in Google's cloud, and the boundary between handled-locally and sent-to-the-cloud is set by Google with no UI indicator. iOS 27, due in autumn 2026, takes the opposite architectural path: Gemini ships as a sandboxed extension at the application layer in a new Extensions framework Apple introduced after a public partnership with Google in early 2026; the extension is opt-in (does not appear in any assistant role unless the user enables it), isolated from system hooks (cannot become the slot, because iOS does not expose the slot to extensions), and invoked only when the user explicitly calls it (the wake word, the home gesture and the system microphone all remain Apple's). The privacy implication is structural: a sandboxed extension can be revoked, audited and constrained by fine-grained permissions; a model installed into the slot inherits the slot, microphone access and default-app reach included. The architecture follows the business, and the business is visible in the published filings: Apple FY2025 revenue is approximately 74 per cent hardware and 26 per cent services with services margin above 70 per cent, the device is the product and privacy a marketing surface; Alphabet 2025 revenue is approximately three quarters advertising (Google Search around 224 billion and YouTube around 40 billion US dollars), with cloud at about 14.57 per cent, and the placement is the product, the data the placement is targeted against operational input. A new assistant in the slot is not a breach and not a leak; the microphone access and the role were already there, the user agreed at some abstract point that their phone would have an assistant. What changed is who is at the other end: voice input that used to be answered by a search agent (route a query to a known endpoint) is now answered by a language model (interpret, decide what data is relevant, decide which extensions or external tools to call, produce a coherent answer) with different defaults about what it stores, summarises and forwards. The verification path, under a minute: Settings, Apps, Default apps, Digital assistant app, choose Gemini or None or Digital assistant from Google if still installed; App management, Gemini, Disable and Force Stop (cannot be uninstalled on most devices, but can be stopped); on Samsung Settings, Apps, Choose default apps, Assistant app. Pixel inline features (Magic Compose, Call Notes, Recorder Summaries, Scam Detection) are per-app under Settings, Apps, choose Messages or Phone or Recorder, AI-feature toggles and Permissions. Trade-off: with None set the long-press and Hey Google do nothing, the phone otherwise works normally. The OS used to ask before changing your browser. It did not ask before changing the model behind your microphone." },
    { date = "Fri, 29 May 2026 00:00:00 GMT", title = "The Licence You Did Not Count", loc = "/blog/the-licence-you-did-not-count", desc = "In the Net Episode 05. The fifth distinct lock-in genus: licence-compliance as a business model. You did not change how you use Java; in January 2023 Oracle changed how it counts you. On 23 January 2023 Oracle replaced its per-user (Named User Plus) and per-processor metrics with the Java SE Universal Subscription, priced per employee, where employee counts the entire organisation (full-time, part-time and temporary staff plus contractors, consultants and agents), not Java users. One server running Oracle's Java makes the whole headcount billable; list pricing starts around 15 US dollars per employee per month, stepping down by volume. A firm of 12,000 staff at the entry band pays a little over 2 million euros a year whether twelve or twelve hundred use Java, because the metric never asked. Oracle holds the brand, the official commercial builds and the TCK compatibility suite. Enforcement is by audit: a Dimensional Research survey commissioned by Azul, a commercial OpenJDK vendor and Oracle competitor, reported 73 per cent of Oracle Java users audited in the previous three years and 81 per cent moving or planning to move to open-source Java; Gartner estimated the per-employee model at two to five times the previous cost; read with the commissioning interest in mind, but corroborated by independent trade reporting. The exit is genuinely open: OpenJDK is the reference implementation Oracle's JDK is built from, and from Java 11 the switch is a reinstall, not a rewrite. The catch is the past: an audit reads download history, and a single legacy Oracle JDK becomes a retroactive claim scoped to the workforce, not the machine, so migration and audit-exposure review are two separate jobs. The price of leaving is a bounded nine-to-fourteen-month OpenJDK migration; the price of staying is recurring and sized by headcount. Escape route: free OpenJDK distributions (Eclipse Temurin from Adoptium, Amazon Corretto, Azul Zulu, Microsoft Build of OpenJDK, BellSoft Liberica, Red Hat, IBM Semeru), all TCK-tested under GPLv2 with the Classpath Exception; inventory every host for legacy Oracle JDK first; and for the same per-core, whole-cluster audit pattern in Oracle Database, PostgreSQL and MariaDB are a complete answer for many workloads. Write once, run anywhere. Licence once, pay for everyone." },
    { date = "Thu, 28 May 2026 00:00:00 GMT", title = "Your Neighbour Is Now Root", loc = "/blog/your-neighbour-is-now-root", desc = "Wire Fire Episode 03. On a shared hosting server you share one machine with hundreds of strangers; this week it emerged that any one of them could become root, and on a shared server root over one account is root over all of them. CVE-2026-48172 is a flaw in the LiteSpeed cPanel plugin, the component that wires the LiteSpeed web server into cPanel and WHM, the control panel that runs a large share of the world's commercial shared hosting. On 19 May 2026 cPanel pulled the plugin through a nightly update, stating it allowed unauthorized root access to the server; on 21 May LiteSpeed shipped a fix (v2.4.5, then 2.4.7 in WHM plugin 5.3.1.0); on 26 May CISA added it to the Known Exploited Vulnerabilities catalogue, confirming use as a zero-day before the patch existed. Rated 10.0 on CVSS v4.0 and 9.8 on v3.1. Every plugin version from 2.3 through 2.4.4 is affected. The mechanism: every customer on a shared server is an ordinary unprivileged user and root belongs to the host alone; the plugin exposed a function named lsws.redisAble, reachable through cPanel's standard JSON API by any logged-in customer, which did not check who was calling and ran with root's authority regardless (CWE-266, incorrect privilege assignment). Any customer, or any attacker with one phished password, could hand it a script that ran as root, taking the whole machine: every other customer's files, databases, credentials and sites. No firewall breach, no kernel exploit, no physical access. Exposure: upgrade to 2.4.7 or remove the plugin; grep logs for cpanel_jsonapi_func=redisAble; audit new accounts; restrict cPanel and WHM by source address. A hosting customer cannot patch this and must ask their provider. The pattern: shared hosting sells a boundary it does not enforce, hundreds of tenants sharing one kernel, one filesystem and one root, with the wall between them living in plugin code and good manners; one fumbled privilege check has a blast radius of the whole server. On FreeBSD the tenant boundary is the jail, kernel-enforced isolation where a process cannot see the host or escalate to its root; the same idea underpins Linux containers and illumos zones. On shared hosting your security boundary is not your account, it is the weakest account on the same machine. You never chose the strangers on your server; this week, one of them could choose to be you." },
    { date = "Wed, 27 May 2026 00:00:00 GMT", title = "The Fire That Reached the Backups", loc = "/blog/the-fire-that-reached-the-backups", desc = "Tales from the Bare Metal Episode 05. The OVHcloud Strasbourg data-centre fire of 10 March 2021. Shortly before 01:00 a fire broke out in a power room at the SBG site; SBG2 was destroyed entirely, SBG1 badly damaged, SBG3 and SBG4 powered down. Around 3.6 million websites and 464,000 domains were unavailable at the peak, close to 18 per cent of OVH's active IP addresses; for customers whose only copy lived on-site, the data was permanently lost. The French BEA-RI report (June 2022) records high humidity near a power inverter in the hour before ignition and stops short of a single definitive cause. The spread is understood: SBG2's free-cooling tower design (built 2011) let waste heat rise and drew outside air in, behaving like a chimney once alight; the floors were wooden, rated for about an hour; and none of the five buildings had an automatic fire-extinguishing system. The systemic context: a mental model in which 'in the data centre' means 'safe' and nobody pictures the building; hosting panels that present backup as a feature to switch on rather than a question of geography, so primary and backup ended in one failure domain by default; and the location of a backup being a checkbox nobody owned. The principle is older than the cloud: 3-2-1, three copies, on at least two media, with at least one off-site, meaning a different failure domain the primary's fire, flood or power event cannot reach. Episode 01 (GitLab) asked you to restore your backups; this episode asks where they physically live, an independent axis. On FreeBSD, zfs send a snapshot to a pool in another region; with restic or borg, replicate to object storage elsewhere. Where it travels: AWS multi-AZ is not multi-region (an Availability Zone is a cluster of buildings, a region is geography); Azure locally-redundant storage is not geo-redundant storage; Kubernetes Velero and etcd snapshots should ship off-cluster and off-region; the on-prem NAS in the same room is a second copy awaiting the same flood. Redundancy that shares a postcode is decoration. The fire does not read your architecture diagram. It reads the floor plan." },
    { date = "Tue, 26 May 2026 00:00:00 GMT", title = "find", loc = "/blog/find", desc = "Technical Beauty Episode 37. A disk is filling up: find /var/log -name '*.log' -mtime +30 -delete clears thousands of stale logs in one line, no loop, no script. Most Unix tools take flags; find takes an expression. The arguments after the starting path are terms in a small query language: primaries that test or act (-name matches a glob, -type f selects regular files, -mtime +30 means modified more than thirty days ago, -size +100M means larger than a hundred megabytes, -newer ref means changed more recently than a reference) and operators that combine them (terms next to each other are an implicit logical AND, -o is OR, ! is NOT, escaped parentheses group). find walks the directory tree and evaluates the expression per file, firing the actions where it is true. That is the reduction: not a flag for every case, but a grammar that composes every case from a small vocabulary, small vocabulary to large expressivity. The -exec action has two forms: {} + batches matches into as few invocations as possible, {} ; runs once per file. For safe composition, find . -type f -print0 | xargs -0 cmd terminates each filename with a null byte so spaces and newlines do not corrupt the pipeline, where the naive for f in $(ls) breaks on the first odd name. FreeBSD ships BSD find in base, BSD-licensed and POSIX-clean, at /usr/bin/find; GNU find (findutils, GPL) grew more primaries (-printf, regex variants) and is a pkg install away as gfind. Dick Haight wrote find, with cpio and expr, for Version 7 Unix (1979), in the Unix Support Group rather than the research room; the researchers were faintly put off by the prefix-expression syntax and kept it because it was useful. Forty-seven years on the grammar is unchanged, and the modern descendant fd (David Peter, sharkdp, Rust, 2017) reproduces the same idea: a small set of predicates over a tree walk. find is the rare Unix tool that is a little language pretending to be a command." },
    { date = "Mon, 25 May 2026 00:00:00 GMT", title = "GELI vs LUKS", loc = "/blog/geli-vs-luks", desc = "The Unix Way Episode 18. Full-disk encryption on FreeBSD and Linux, two shapes. A laptop left on a train with full-disk encryption is an expensive paperweight and a drive full of noise; without it, your keys, mail and customers. GELI is FreeBSD's disk-encryption framework and not a standalone product but a GEOM class: GEOM is the modular block-storage framework in which mirroring, striping, labelling and encryption are each a class consuming a provider and presenting a provider, so encryption is one more composable transform. geli init -e AES-XTS -l 256 -a HMAC/SHA256 sets up AES-256-XTS (the default AES-XTS key length is 128, so -l 256 is worth specifying) with key strengthening via PKCS#5v2 (PBKDF2); geli attach creates /dev/ada1.eli, which takes UFS via newfs or becomes a ZFS vdev; the -a HMAC/SHA256 flag adds per-sector authenticated encryption so a flipped bit is detected, not silently decrypted; encrypted swap uses one-time keys via geom_eli in rc.conf. LUKS (Linux Unified Key Setup) is the standard, used through cryptsetup: luksFormat writes a LUKS2 header (default since cryptsetup 2.1, 2019, up to 32 key slots); the default cipher is aes-xts-plain64 256-bit (AES-256-XTS) and the default KDF is argon2id, a memory-hard function (around 1 GiB and several hundred milliseconds per attempt) that is genuinely ahead of GELI's PBKDF2 because the attacker must provision memory per guess; cryptsetup open creates /dev/mapper/secret through device-mapper over dm-crypt; authenticated encryption is added with --integrity, a second device-mapper target dm-integrity beneath dm-crypt; persistence via /etc/crypttab, composing with LVM in either order. The architectural difference: on FreeBSD encryption is a GEOM class that stacks uniformly with gmirror, gstripe and glabel under one vocabulary, with integrity a flag rather than a subsystem; on Linux the same power is assembled from separate subsystems (LUKS header, dm-crypt, dm-integrity, dm-verity, LVM, mdadm), each its own device-mapper target with its own tooling. The modularity is why LUKS2 could adopt argon2id ahead of GELI; the coherence is why the FreeBSD answer to encrypt, mirror and detect tampering is three flags and one mental model. Both default to AES-256-XTS and both turn a stolen drive into noise. One framework of uniform parts, or several specialised parts composed. The Unix way prefers the version you can hold in one hand." },
    { date = "Sun, 24 May 2026 00:00:00 GMT", title = "Why We Mock Everything", loc = "/blog/why-we-mock-everything", desc = "On Second Thought Episode 09. A new test file: before a single assertion, you build a world (a fake database, a fake clock, a fake mailer), forty lines of fakes and two of test, and a mock-free test would look almost negligent. The unit test was born pure: Kent Beck's SUnit for Smalltalk (1994), adapted into JUnit with Erich Gamma (1998), tested library code (parsers, algorithms, pure functions) with nothing to fake because there was no world to touch. We carried the practice into application code, which is nothing but world (a database, a queue, a payment API, a clock, a mailer), and to keep calling the tests unit tests we faked the world; dependency injection arrived to give every collaborator a seam, and the architecture was reshaped so the fakes would fit. Martin Fowler's 2007 essay Mocks Aren't Stubs named the classicist and mockist camps; the London school (Freeman and Pryce, Growing Object-Oriented Software, Guided by Tests, 2009) is disciplined, but the industry generalised it until unit test came to mean mocked test. The cost arrives in three layers: daily friction (40 lines of setup to 2 of assertion; a refactor with no behaviour change turns 50 tests red because mockist tests assert on interactions, not behaviour); false confidence (400 green tests, broken checkout in production, because every dependency was a mock); and the hidden design cost (interfaces, seams and injection points that exist only to receive a mock, so the code is shaped by the need to be mockable; the mock count is a reading of how far logic and I/O were stirred together). The most testable software ever written has no mocks at all: a Unix filter (grep, awk, sort in the FreeBSD base) is pure, text in, text out, isolated by construction because the kernel and the shell handle the world. Doug McIlroy's pipe (1973) was, in modern terms, a functional core with an imperative shell. Gary Bernhardt named that shape functional core, imperative shell in his 2012 talk Boundaries; Alistair Cockburn called it ports and adapters (hexagonal architecture, renamed 2005). A pure core needs no mocks; a thin shell needs only a few real integration tests. A mock is not a tool, it is a reading on a gauge of how far the logic was allowed to wander into the world." },
    { date = "Sat, 23 May 2026 00:00:00 GMT", title = "The Box Ticked While You Read This", loc = "/blog/the-box-ticked-while-you-read-this", desc = "Not in the Brief Episode 04. You are reading this on LinkedIn. Somewhere in your settings sits a switch labelled Data for Generative AI Improvement; for most of us it is on, and none of us turned it on. The setting lets LinkedIn use your profile information and public content (posts, articles, comments) to train generative AI models, both its own and those of its affiliate Microsoft, which owns LinkedIn and runs the Azure OpenAI service; private messages are stated to be excluded. The toggle appeared already enabled with the 18 September 2024 privacy-policy update, opt-out only; 404 Media reported LinkedIn had begun using member data before the terms were updated to disclose it, and the company said it would update them shortly. After the UK Information Commissioner's Office raised concerns, LinkedIn paused training for the EEA, Switzerland and the UK until further notice. On 3 November 2025 it switched those regions on as well, alongside Canada and Hong Kong. The legal basis relied on is legitimate interest under the GDPR, which does not require prior consent but requires an objection route. The opt-out is forward-only: switching it off stops future training but does not retract content already used, so public content posted before the regional cut-off is already in scope. This is not a breach and not surveillance: the content is what the member chose to make public, and the controlling setting is documented and reachable in three clicks. The judgement is about architecture and process, not motive: default-on with a quiet notice treats the absence of objection as the presence of consent and places the entire burden of awareness on the member. The verification path: Settings and Privacy, Data Privacy, Data for Generative AI Improvement; thirty seconds to check your own switch." },
    { date = "Fri, 22 May 2026 00:00:00 GMT", title = "The Renewal You Did Not Survive", loc = "/blog/the-renewal-you-did-not-survive", desc = "In the Net Episode 04. You bought VMware once, outright, as a perpetual licence; in November 2023 a 69 billion dollar (around 64 billion euro) Broadcom acquisition closed, and over eighteen months the thing you owned was converted into a thing you rent. Adobe, LinkedIn and AWS built their lock-in into the product; VMware's was built into a transaction the customer was never party to. Three hooks: perpetual licences ended (subscription only, renewed yearly, or support and security updates stop); the free ESXi edition was withdrawn in early 2024 and quietly reinstated in April 2025 as ESXi 8.0 Update 3e, a non-production build with no support that cannot connect to vCenter, announced in release notes; per-CPU licensing became per-core, repackaged into VMware vSphere Foundation (VVF) and VMware Cloud Foundation (VCF) bundles that include NSX networking and vSAN storage whether or not the customer runs them. VMware held roughly 70 per cent of the server-virtualisation market on Gartner's 2024 figures; Gartner projects 40 per cent by 2029. Ingram Micro ended its VMware distribution in select regions from early January 2025. A March 2025 72-core minimum per order would have forced a 32-core cluster to buy 72 cores, a 125 per cent increase for nothing; after backlash it was withdrawn, with Broadcom stating it had never announced a price change. AT&T sued Broadcom in the New York State Supreme Court in August 2024 to keep support under a pre-acquisition agreement without buying subscription bundles. Reported renewal increases range from 150 per cent into four figures. The escape route is a stack, not a product: bhyve for VMs, jails for containers, ZFS for storage, all in the FreeBSD base and none of it up for acquisition; Sylve as the optional Proxmox-style web UI (v0.2.x, 2026, young but productive for FreeBSD-first shops); Proxmox VE on KVM and QEMU as the mature mass-migration target, with XCP-ng, Nutanix AHV and OpenStack as alternatives; migration over the open OVF and qcow2 path. You owned a hypervisor. You were handed a subscription. The hypervisor, it turns out, was never the expensive part." },
    { date = "Thu, 21 May 2026 00:00:00 GMT", title = "Your Editor Extensions Run as You", loc = "/blog/your-editor-extensions-run-as-you", desc = "Wire Fire Episode 02. On 18 May 2026 an attacker published a poisoned version of a popular Visual Studio Code extension, a trojanised build of Nx Console (nrwl.angular-console) version 18.95.0, on the VS Code Marketplace; it was live for roughly eleven minutes. That was long enough to reach a GitHub employee's laptop and exfiltrate around 3,800 of GitHub's own internal source-code repositories. GitHub detected the intrusion on 19 May and confirmed it publicly on 20 May, attributing it to an employee device compromised through the extension. The attacker, TeamPCP, tracked by Google Threat Intelligence as UNC6780, specialises in supply-chain attacks against developer tooling and is reportedly asking more than 50,000 US dollars for the stolen material; GitHub reports no evidence as of the confirmation that customer data, enterprise accounts or user repositories were touched. The mechanism: a VS Code extension runs with the full privileges of the developer who installed it, with no sandbox; the moment a workspace opens, the activation code runs immediately and automatically, and can read any file the user can read, run any command the user can run, and reach any credential, token or SSH key on the machine. The poisoned build fetched an obfuscated payload on activation and harvested exactly that. No firewall was breached, no server exploited, no password brute-forced: the attacker was invited in by an automatic activation of trusted code. Exposure check: ran nrwl.angular-console 18.95.0 around 18 May? Assume compromise, rotate every reachable credential, revoke tokens, check outbound connections; pin extension versions and disable auto-update; audit installed extensions; treat editor extensions as production dependencies. The pattern: the editor is now part of the supply chain. An extension marketplace is a package registry by another name, with the same arbitrary-code risk as npm and far less scrutiny, because installing an extension feels like configuring the editor rather than adding a dependency. On FreeBSD the structural fix is Capsicum, capability-mode sandboxing, so a process holds only the authority it was handed; editors are not built that way yet, on any platform. The home of the world's source code was read through a plugin to the world's most popular editor; both belong to the same company." },
    { date = "Wed, 20 May 2026 00:00:00 GMT", title = "The Unit That Crossed a Boundary", loc = "/blog/the-unit-that-crossed-a-boundary", desc = "Tales from the Bare Metal Episode 04. The Mars Climate Orbiter, launched 11 December 1998, fired its main engine to enter orbit on 23 September 1999, passed behind Mars and was never heard from again. The 193-million-dollar spacecraft (327.6 million total mission) travelled 670 million kilometres over nine months and was lost to a number with no unit written on it. The insertion burn was designed to leave it at 226 km altitude; reconstruction showed it reached approximately 57 km, deep in the atmosphere, where a craft built for vacuum does not survive. The Mishap Investigation Board Phase I report of 10 November 1999 found the root cause was a unit mismatch at a software interface: Lockheed Martin's ground software output thruster impulse in pound-force seconds (imperial), while NASA JPL's navigation software expected newton-seconds (SI). One pound-force second equals 4.45 newton-seconds; every impulse was read 4.45 times too small for nine months. The number was correct; it crossed the interface with no unit attached and each side assumed its own. Three systemic conditions allowed it: the interface spec required metric but was a document not a runtime check; the discrepancy was visible in cruise navigation data months early but raised informally and never escalated; no end-to-end test ran both systems against the same manoeuvre. The principle: in science and engineering, measure in metric (SI); where two systems must still meet, make the unit travel with the number through types the compiler checks (Rust newtypes, F# units of measure), fields the parser demands, or names the variable carries (timeout_ms, not timeout). On FreeBSD the discipline is visible in dd bs=1M, sysctl units and loader.conf tunables. The same mismatch hides in the gigabyte-versus-gibibyte gap: a 1 TB decimal drive displays as ~931 GiB; the IEC defined the binary ladder (KiB, MiB, GiB, TiB) in 1998; prefer the explicit binary prefixes when you mean powers of two." },
    { date = "Tue, 19 May 2026 00:00:00 GMT", title = "grep", loc = "/blog/grep", desc = "Technical Beauty Episode 36. grep was written by Ken Thompson at Bell Labs in November 1973 after Doug McIlroy asked for a tool that would let Lee McMahon analyse the Federalist Papers by pattern. The story, told later by Brian Kernighan in 'The Unix Programming Environment', has Thompson disappearing into his office for about an hour and returning with grep, named after ed's g/re/p command (global, regular-expression, print). The surface is famously austere: one pattern, n files, matching lines on stdout, composable through pipes. Variants merged over the years: egrep became grep -E (extended regex), fgrep became grep -F (fixed strings), pcregrep became grep -P where built (Perl-compatible regex). The interior of GNU grep, carried for years by Mike Haertel through the late 1980s and 1990s, uses Boyer-Moore (Robert Boyer and J Strother Moore, 1977) for fixed-string searches, Crochemore-Perrin two-way string matching (1991) for harder patterns with a fixed prefix or suffix, Thompson's 1968 NFA construction for full regex, and mmap rather than stdio on the input. Haertel's August 2010 freebsd-current note stated the principle: 'The key to making programmes fast is to make them do practically nothing.' Modern grep scans several gigabytes per second on commodity hardware. FreeBSD ships bsdgrep in base since around 2010, a BSD-licensed lean implementation; OpenBSD and NetBSD follow the same pattern; GNU grep is one pkg install gnugrep away. The shape (pattern plus files plus matching lines on stdout) has stayed identical for fifty-three years; ack (Andy Lester, 2005, Perl, .gitignore-aware), ag, the silver searcher (Geoff Greer, 2011, C) and ripgrep (Andrew Gallant aka BurntSushi, 2016, Rust, SIMD) each rewrote the implementation, none changed the interface. Stephen Cole Kleene formalised regular sets in 1956 as a mathematical object; Thompson, in 1968, wrote the first practical implementation in his CACM paper; grep, in 1973, made regex the default search interface for the working programmer." },
    { date = "Mon, 18 May 2026 00:00:00 GMT", title = "DTrace vs eBPF", loc = "/blog/dtrace-vs-ebpf", desc = "The Unix Way Episode 17. DTrace was designed at Sun Microsystems by Bryan Cantrill, Mike Shapiro and Adam Leventhal beginning in 2001, with a working implementation in November 2003 and Solaris 10 GA in January 2005. The principle was rather radical for its time: instrument any kernel or userland probe in production with zero overhead when disabled and minimal overhead when enabled; the script language was deliberately Turing-incomplete so the compiler could prove every probe terminated within bounded time and memory before loading. John Birrell ported DTrace to FreeBSD; it landed in 7.1-RELEASE on 6 January 2009. The probe count on a modern host runs into the tens of thousands. Linux could not adopt DTrace upstream because the CDDL is a file-level weak copyleft that accepts coexistence with any other licence, while the GPL is strong copyleft that demands the combined work be relicensed to GPL; the asymmetry is structural and the block was in the GPL's design rather than the CDDL's behaviour. The Linux rebuild started from a substrate that had existed since 1992: BPF, the Berkeley Packet Filter by Steven McCanne and Van Jacobson. Alexei Starovoitov (then PLUMgrid, now Meta) and Daniel Borkmann (then Cisco, now Isovalent) generalised BPF into eBPF, merged in Linux 3.18 on 7 December 2014; the in-kernel verifier proves termination, bounded memory access and valid pointers before loading. BCC (BPF Compiler Collection) by Brenden Blanco at IO Visor arrived in 2015. bpftrace by Alastair Robertson (then University of Manchester) was announced by Brendan Gregg as 'DTrace 2.0 for Linux' in October 2018, fifteen years after the original DTrace. The bridge figure is Brendan Gregg himself, co-author with Jim Mauro of the 2011 DTrace book at Sun/Joyent and author of the 2019 BPF Performance Tools book at Netflix. The shape was always the same; the journey was a great deal longer." },
    { date = "Sun, 17 May 2026 00:00:00 GMT", title = "Why We Containerise Everything", loc = "/blog/why-we-containerise-everything", desc = "On Second Thought Episode 08. The container is now the unit of thought, not merely a deployment artefact. Three currents converged. Isolation: Poul-Henning Kamp wrote Jails for FreeBSD in 1999 as a kernel-native abstraction with no daemon, shipped in FreeBSD 4.0 in March 2000; Solaris Zones followed in 2004; Linux gained namespaces and cgroups from 2006 to 2008 as eight separate types requiring composition by the caller; LXC composed them in 2008; Docker wrapped the result, replaced LXC with libcontainer, added a daemon, and branded the technique in 2013. Org-shape: Scrum was codified between 1995 (Sutherland and Schwaber's OOPSLA paper) and 2001 (the Agile Manifesto) and split organisations into sprint-shaped teams; Melvin Conway's 1968 paper had explained in advance that software mirrors its organisation's communication structure. Runtime: Node.js was released in 2009 by Ryan Dahl as single-threaded by design; multi-core hardware required multi-container deployment, and the fix became more containers and an orchestrator to schedule them. The bill arrives in four layers: image bloat (node:22 over a gigabyte; a 50 MB application is 1 to 5 per cent of the bytes moved); the supply chain travelling with the image (May 2026: 172 npm and PyPI packages, 403 versions, ~518 million cumulative downloads inside 48 hours); daemon overhead (dockerd above 5 GB at 183 containers); network tax (a function call costs about a microsecond, a network call between services costs one to five milliseconds, so ten services pay thirty milliseconds before business logic begins; cloud-native benchmarks show +140% p99 latency, +300% memory, +260% network I/O against the monolith; Istio's sidecar adds 2.5 ms at p90 and 60 MB RAM per proxy). Documented retreats: Amazon Prime Video returned video monitoring from Lambda and Step Functions to a monolith on EC2 in 2023 for ~90 per cent cost reduction; Segment consolidated 140 microservices into a single monolith in 2017; Istio quietly merged its own control plane back into a single binary in 2023; 37signals left AWS entirely in 2023 with hardware recouped inside year one and ~$7M saved across five years. Alternatives: FreeBSD Jails (kernel-native, no daemon), Capsicum (FreeBSD 9.0, 2012, capability-based isolation), OpenBSD pledge (5.9, 2015) and unveil (6.4, 2018) for syscall and filesystem narrowing, Go and Rust finding their own cores as single static binaries. The honest question is whether the isolation question, the runtime question and the team question were ever the same question." },
    { date = "Sat, 16 May 2026 00:00:00 GMT", title = "The Screenshot Diary", loc = "/blog/the-screenshot-diary", desc = "Not in the Brief Episode 03. Microsoft Recall on Copilot+ PCs captures snapshots of the screen at regular intervals, indexes them with a local AI model and exposes natural-language search across the user's past activity. NPU requirement >= 40 TOPS; OEMs Microsoft, Dell, HP, ASUS, Lenovo, Samsung. Announced at Microsoft Build, May 2024, with default-on activation and mostly-cleartext SQLite storage; withdrawn in June 2024 after Alexander Hagenah's TotalRecall demonstrated trivial extraction; redesigned through late 2024; re-released April 2025 on a Virtualisation-Based Security (VBS) Enclave with AES-256-GCM at-rest encryption with per-record keys, key material sealed against the TPM and Windows Hello Enhanced Sign-In Security as the unlock gate. Setup dialog now defaults to disabled; managed devices have Recall removed by default. In March 2026 Hagenah published TotalRecall Reloaded: an ordinary user-level program with no admin rights and no kernel exploit that injects into AIXHost.exe (the Recall timeline-rendering process) after Windows Hello unlock and reads decrypted snapshots, OCR text and metadata directly from the process's address space. Microsoft VP David Weston response in The Verge, April 2026: 'consistent with intended protections and existing controls, does not represent a bypass of a security boundary'. In Hagenah's summary: the vault door is titanium, the wall next to it is drywall. The opt-in default in the setup dialog is the result of public pressure, not original design. Verification path: Settings > Privacy & security > Recall & snapshots; in-app exclusions; Group Policy User Configuration > Administrative Templates > Windows Components > Windows AI > 'Turn off saving snapshots for Windows'; Intune CSP WindowsAI / DisableAIDataAnalysis = 1; forensic path %LOCALAPPDATA%\\CoreAIPlatform.00\\UKP." },
    { date = "Fri, 15 May 2026 00:00:00 GMT", title = "The Architecture You Did Not Design", loc = "/blog/the-architecture-you-did-not-design", desc = "In the Net Episode 03. In March 2024 AWS waived data-egress fees for customers wishing to leave; two years on, leaving is harder than ever and egress is no longer the reason. The lock-in lives in three layers, only one of which gets discussed. Egress layer: Free Data Transfer Out For Leaving (5 March 2024), gated on good standing, more than 100 GB, intention to move all data, 90 days, account-level review, additional scrutiny on repeated applications; arrived in the window before EU Data Act Article 25 prohibits all switching charges from 12 January 2027. Runtime layer: Aurora's six-way replicated log-structured shared-storage fabric, Babelfish T-SQL, Aurora Machine Learning, Aurora Limitless Database, DynamoDB without an on-prem equivalent, Lambda wired to EventBridge, SQS, SNS, CloudWatch, X-Ray; each AWS-specific decision locally rational, the cumulative effect is the workload becomes an AWS workload. Identity layer: IAM policy language (JSON grammar over ARNs), ARNs not portable, KMS keys that never leave the service in plaintext and cannot cross regions let alone clouds, Identity Center permission sets translated into IAM roles at session time; five years of encoded security history in JSON. AWS holds ~30% of the global cloud infrastructure market in Q1 2026 (Synergy Research), the Big Three ~65%, global quarterly spend ~$129B, +35% YoY. 37signals' published account: ~$3.2M/y on AWS in 2022, under $1M on-prem in 2024, ~$2M annual savings ongoing, hardware ($700k Dell + $1.5M Pure Storage for 18 PB) recouped inside year one. Flexera 2025: 21% of cloud workloads already repatriated. Escape route: portable identity (Keycloak, Authentik, Zitadel speaking OIDC, SAML 2.0, SCIM), policy as code (Open Policy Agent + Crossplane), EU IaaS (Hetzner ~14x AWS value-per-compute per Callista Feb 2026, Scaleway ~5x with free egress, OVHcloud, IONOS), open-source data services (PostgreSQL, Apache Cassandra, ScyllaDB, MongoDB, MinIO and Garage for the S3 API). You can take your data with you. The architecture stays behind. The architecture is the more expensive part." },
    { date = "Thu, 14 May 2026 00:00:00 GMT", title = "npm Is on Fire", loc = "/blog/wire-fire-npm-is-on-fire", desc = "Wire Fire Episode 01. Six weeks of supply-chain compromise on the npm registry, four waves, ending on 12 May 2026 with the Shai-Hulud worm source going public. 31 March: state-sponsored operators backdoor axios 1.14.1 and 0.30.4 via plain-crypto-js@4.2.1 as a postinstall payload, three hours live, tagged latest; ~100M weekly downloads exposed; Microsoft attribution Sapphire Sleet (DPRK), Mandiant tracks the cluster as UNC1069. 29 April: Mini Shai-Hulud against four SAP-related npm packages. 11 May 19:20-19:26 UTC: 84 versions across 42 TanStack packages in six minutes, scaling to 172 packages and 403 versions across npm and PyPI in 48 hours; @uipath, @mistralai/mistralai, OpenSearch, Guardrails AI also affected; ~518M cumulative downloads. The 11 May automation chains three GitHub Actions weaknesses: pull_request_target Pwn Request, Actions cache poisoning, OIDC token extraction. 12 May: vx-underground reports the fully weaponised Shai-Hulud source is now publicly available. 2025 baseline: 454,648 malicious npm packages, more than 99 per cent of all open-source malware targets npm. Actions for today: npm config set ignore-scripts true; audit the lockfile; rotate every reachable credential; pin transitive dependencies; isolate untrusted installs in FreeBSD jails. The architectural answer is older than the problem: FreeBSD VuXML for advisories, jails and Capsicum for blast-radius containment, the FreeBSD ports model with named maintainers and human review." },
    { date = "Wed, 13 May 2026 00:00:00 GMT", title = "The Regex That Ran Unbounded", loc = "/blog/the-regex-that-ran-unbounded", desc = "Cloudflare WAF outage, 2 July 2019. 13:42 UTC: an engineer deploys one new managed XSS-detection rule via Quicksilver, Cloudflare's distributed key-value store, global in seconds. Within seconds every Cloudflare edge server is at 100 per cent CPU and HTTP traffic stops moving. The forty-five-character rule contained (?:.*=.*); the catastrophic shape reduces to .*.*=.*, two greedy quantifiers in sequence followed by a literal and another quantifier. On PCRE, a backtracking matcher with no runtime budget, the pattern triggers exponential search on inputs that do not contain an equals sign; multiplied by every concurrent request and every CPU core on every edge server, the result is global saturation. 13:45 first synthetic-test alerts, 14:00 WAF identified, 14:07 global terminate executed, 14:09 traffic and CPU normal, 14:52 WAF re-enabled after rollback. Twenty-seven minutes on a service that fronts a sizeable share of the public internet. Three systemic conditions: an author optimising for detection coverage with no CPU-time profiling in the test harness; a PCRE engine with no built-in budget after an earlier CPU-usage guard had been removed and not reinstated; a deployment path with no staged rollout, where the dashboard that would have disabled the rule ran on the same edge network and was unreachable. Cloudflare's announced preventive measures (John Graham-Cumming postmortem, 12 July 2019): switch to RE2 or the Rust regex crate (linear-time, refuse exponential patterns at compile time); reintroduce CPU-usage protection; profile in CI on pathological inputs; staged rollout SOP for managed rules, with the global lane retained for kill switches; separate the control-plane dashboard from the edge network. The FreeBSD lesson: rctl(8) gives the CPU and memory budget the engine cannot enforce. Tales from the Bare Metal Episode 03." },
    { date = "Tue, 12 May 2026 00:00:00 GMT", title = "tcpdump", loc = "/blog/tcpdump", desc = "tcpdump is the thin command-line filter one types at three in the morning. The technical beauty is the layering: tcpdump (userspace tool, filter language, one line per packet) on libpcap (compiles the filter, manages the capture session, defines the .pcap file format) on BPF (in-kernel pseudo-machine, filters before copy to userspace). Van Jacobson, Craig Leres and Steven McCanne wrote tcpdump at Lawrence Berkeley Laboratory in 1988. McCanne and Jacobson published 'The BSD Packet Filter' in December 1992; presented at USENIX Winter 1993 in San Diego, Best Student Paper. The new register-based pseudo-machine replaced Sun's stack-based NIT and measured up to 20x faster than its predecessor's filter and up to 100x faster than NIT overall on the same hardware. libpcap was factored out of tcpdump around 1995 and became the de facto packet-capture library: Wireshark, tshark, dumpcap, Zeek (formerly Bro), snort, suricata, nmap, ngrep and dsniff all sit on it. tcpdump.org was founded in 1999 by Michael Richardson and Bill Fenner, where the project still lives. Linux did not have BPF in the original sense; in December 2014 Alexei Starovoitov shipped eBPF in Linux 3.18, extending the architecture with a wider register file, new instructions, a verifier, and attachment points beyond packet capture (system calls, tracepoints, kprobes). bcc, bpftrace and Cilium are eBPF consumers; the lineage runs back to the same 1993 paper. Technical Beauty Episode 35." },
    { date = "Mon, 11 May 2026 00:00:00 GMT", title = "netstat vs ss", loc = "/blog/netstat-vs-ss", desc = "On a busy Linux load balancer netstat -anp keeps one waiting; on FreeBSD the same workload returns at once. Both speak Unix text and pipe into grep, awk and sort; only one was built the way Unix tools are built. FreeBSD netstat has been in base since 4.2BSD shipped TCP/IP in August 1983; it asks the kernel through sysctl net.inet.tcp.pcblist, net.inet.udp.pcblist, net.local.stream.pcblist and so on; one structured call, formats columns, exits; sub-second on sixty thousand sockets. Linux net-tools netstat reads /proc/net/tcp, a kernel-rendered ASCII dump that is readable but not askable; the tool re-parses every line, walks /proc/<pid>/fd, filters in userspace; ten to fifteen seconds on the same workload. The package has had no new release since 2011; the maintainer (Fred N. van Kempen and contributors) publicly attempted deprecation in 2009. Alexey Kuznetsov restored the Unix pattern with ss by adding NETLINK_INET_DIAG in Linux 2.6.14 (October 2005), generalised to NETLINK_SOCK_DIAG in 3.3 (March 2012), adding AF_UNIX. ss opens one netlink socket, sends a structured query, receives only the matching records; kernel-side filtering through expressions like ss -tan state established '( dport = :443 )'. The shape ss restored is the shape sysctl has been running on FreeBSD since 1983. McIlroy text-streams live in the tool's mouth; a file shaped like text is not the same thing. The Unix Way Episode 16." },
    { date = "Sun, 10 May 2026 00:00:00 GMT", title = "Why We Render Everything in the Browser", loc = "/blog/why-we-render-everything-in-the-browser", desc = "Brendan Eich wrote JavaScript in ten days in 1995, for form validation, without a standard library worth the name. AJAX 2005 had a real argument; Gmail and Maps earned it. The brochure inherited it without re-examination. HTTP Archive Web Almanac 2025: median 697 KB JavaScript on home pages, 632 KB inner, 90th percentile 1,979 KB, 10th percentile 87 KB. The bill arrives in three layers: client power, battery, and accessibility; a duplicated server runtime in Node.js displacing PHP, Ruby, Python, Go for non-technical reasons; and an npm dependency cloud (~500K malicious packages observed, Sept 2025: 18 packages with 2.6B weekly downloads in a single coordinated attack) supervised by a second cloud of Dependabot, Snyk, Renovate. Wikipedia on MediaWiki/PHP 8.3, GOV.UK with progressive enhancement mandated, Hacker News in Arc/Common Lisp, HEY/Basecamp on Hotwire, HTMX at 14 KB minified by Carson Gross, Netflix removing client React for +50% Time to Interactive, and Cloudflare Pingora replacing nginx+Lua at ~70% less CPU and ~67% less memory at over a trillion requests per day prove the alternative is in production. Reactivity is solved in single-digit kilobytes by Hotwire Turbo Streams, HTMX, Phoenix LiveView, Laravel Livewire, ASP.NET Blazor Server. The fastest bundle is the one that is never shipped. On Second Thought Episode 07." },
    { date = "Sat, 09 May 2026 00:00:00 GMT", title = "The Vault That Stays Open", loc = "/blog/the-vault-that-stays-open", desc = "Open Microsoft Edge. The browser silently decrypts every saved password into msedge.exe at launch and keeps the entire vault in cleartext in process memory until the browser is closed, regardless of any actual use of the credentials. Disclosed by Tom Joran Sonstebyseter Ronning at Palo Alto Networks Norway's BIG Bite of Tech, 29 April 2026; LinkedIn demonstration video 4 May 2026. Microsoft, in its own words, calls the architecture by design and balances performance, usability and security; not classified as a security issue. Chrome since 2024 decrypts lazily and binds keys to the SYSTEM-level process via Application-Bound Encryption; Brave, Opera and Vivaldi inherit the lazy behaviour. Edge alone among the major Chromium browsers takes neither step. Five minutes with Process Explorer or System Informer to verify; KeePassXC or Proton Pass as the honest replacement; Group Policy PasswordManagerEnabled = 0 disables it estate-wide. Not in the Brief Episode 02." },
    { date = "Fri, 08 May 2026 00:00:00 GMT", title = "The Reach You Did Not Earn", loc = "/blog/linkedin-reach-you-did-not-earn", desc = "LinkedIn 2002, 1.1 billion users in 2026. The reach algorithm penalises external links (~18.8 per cent reduction in van der Blom 2026, n = 1.3M), penalises thematic breadth via a topic fingerprint, and is computed by 360Brew, a 150-billion-parameter decoder-only foundation model on Mixtral 8x22 (Firooz et al., arXiv:2501.16450). The native CSV export gives first-degree names without the graph. Microsoft is a DMA gatekeeper; LinkedIn is not, by regulatory choice. The exit door opens onto a car park. In the Net Episode 02." },
    { date = "Thu, 07 May 2026 00:00:00 GMT", title = "Lua Tables: The Configuration Format That Admits What It Is", loc = "/blog/lua-tables-config", desc = "1993, PUC-Rio Tecgraf: Ierusalimschy, de Figueiredo and Celes merged DEL and Sol into Lua, originally as a portable configuration language for Petrobras. Lua's table is array, hash, record, object and namespace in one construct. Default declarative; expressive form opt-in. FreeBSD's boot loader reads /boot/lua/loader.lua since 2018, Neovim's init.lua since 2021, OpenResty runs Cloudflare's edge, World of Warcraft's UI has been Lua since 2004. The Norway problem cannot occur because Lua has no opinion about your country codes. The honest format is the one that admits what it is." },
    { date = "Wed, 06 May 2026 00:00:00 GMT", title = "The Command That Removed Too Much", loc = "/blog/the-command-that-removed-too-much", desc = "AWS S3 US-EAST-1, 28 February 2017, 09:37 PST. An authorised engineer presses Enter on a routine capacity-removal command with one mistyped argument. Index and placement subsystems both lose capacity. Four hours seventeen minutes later, half the public-facing web is back. For two of those hours the AWS Service Health Dashboard could not update because its console depended on S3. Three systemic conditions: a tool with no floor of safety, a recovery path aged unrehearsed, and a status surface that shared fate with the system it described. Tales from the Bare Metal Episode 02." },
    { date = "Tue, 05 May 2026 00:00:00 GMT", title = "doas", loc = "/blog/doas", desc = "In July 2015 Ted Unangst grew tired of negotiating with sudo on OpenBSD and wrote his own: roughly 1,100 lines of C plus a small yacc grammar, default in OpenBSD 5.8 by October 2015. The configuration fits on a postcard. No PAM, no LDAP, no plugin loader, no /etc/doas.d/. Sudo's CHANGELOG carries Baron Samedit (CVE-2021-3156, hidden since 2011), Pwfeedback, sudoedit, and the 2025 host-option and chroot vulnerabilities. The upstream OpenBSD doas, in the same period, has carried no comparable critical CVE. A tool that does less has less to break." },
    { date = "Mon, 04 May 2026 00:00:00 GMT", title = "One Clock, One Tool, Three Distros", loc = "/blog/one-clock-one-tool-three-distros", desc = "Ask a Linux admin which time daemon their server runs. Pause for the silence. NTP since 1985 by David L. Mills. On FreeBSD: ntpd in base since 4.x in 2000, one line in /etc/rc.conf, the same answer for twenty-five years. On Linux: ntpd the legacy original, chrony the modern Red Hat-maintained replacement (default on Fedora/RHEL/Arch), and systemd-timesyncd the SNTP-only minimalist (default on Ubuntu since 18.04, ignores /etc/ntp.conf). Three answers because the distribution committees could not converge. The cost is paid every time an admin inherits a server." },
    { date = "Sun, 03 May 2026 00:00:00 GMT", title = "Why We Reach for the Layer", loc = "/blog/why-we-reach-for-the-layer", desc = "The ORM hides the SQL. The cache hides the ORM. The service mesh hides the services. The operator hides the YAML, which hides the kubelet, which hides the container, which hides the process. Dijkstra 1968 and Parnas 1972 introduced layers as a discipline to contain complexity; somewhere between Parnas and the cloud generation, containing became postponing. Lehman 1974 named the cost; Karlton named the diagnostic. SQLite (~156k LOC, ~92M-line test suite), awk (1977, unchanged), pf (one syntax since 2001) are the proof that reduction is achievable. The plaster is cheap. The wound is not." },
    { date = "Sat, 02 May 2026 00:00:00 GMT", title = "The Browser That Brought Its Own AI", loc = "/blog/the-browser-brought-its-own-ai", desc = "Open chrome://on-device-internals. If your machine qualifies, Chrome has quietly downloaded a multi-gigabyte Gemini Nano language model. Any website can call it through an API in JavaScript with no permission prompt. Seven APIs (LanguageModel, Summarizer, Translator, Writer, Rewriter, Proofreader, LanguageDetector). The geolocation dialog still exists. The model dialog never did. Not in the Brief opens with the documented mechanics, the awareness path, and the same pattern in Edge, Brave, Firefox, Arc and Safari." },
    { date = "Fri, 01 May 2026 00:00:00 GMT", title = "The Subscription You Did Not Ask For", loc = "/blog/the-subscription-you-did-not-ask-for", desc = "Adobe CS6 in 2012: ~2,500 EUR per seat, perpetual. Adobe Creative Cloud in 2026: ~743 EUR per seat per year, in perpetuity. In the Net opens with the textbook lock-in: PSD/AI/INDD as proprietary anchors, Cloud Libraries that decay on cancellation, a 50 per cent Early Termination Fee the US DOJ took to court in June 2024, an eighty per cent market share that makes the lock-in industry-wide, and a February 2024 TOS update Adobe later walked back. The alternatives are real and professional; two of them changed hands in eighteen months." },
    { date = "Thu, 30 Apr 2026 00:00:00 GMT", title = "The Backup That Wasn't", loc = "/blog/the-backup-that-wasnt", desc = "GitLab, 31 January 2017, 23:30 UTC. Visually identical terminals, one rm -rf, 300 GB removed in two seconds. The hard part: eighteen hours of discovering that none of the five backup mechanisms had been working. pg_dump silently broken since an upgrade, alert emails rejected by DMARC, LVM snapshots scoped for staging, Azure snapshots never enabled, WAL archiving never configured. Tales from the Bare Metal opens with the principle older than every database: backups are not backups until they have been restored." },
    { date = "Wed, 29 Apr 2026 12:00:00 GMT", title = "The Width You Never Had to Measure", loc = "/blog/the-width-you-never-had-to-measure", desc = "A card in a 280-pixel sidebar and the same card in a 1100-pixel dashboard. The team wrote a ResizeObserver, doubled the CSS, and accepted the occasional flash of unstyled content. Container queries collapsed it into two declarations: container-type on the parent, @container rules on its descendants. Cross-browser stable since Firefox 110 on 14 February 2023, global usage 94 per cent in March 2026. The cascade was capable all along." },
    { date = "Wed, 29 Apr 2026 00:00:00 GMT", title = "A Small Adventure Between Two Prices", loc = "/blog/publisher-shop-launch", desc = "Amazon since World Book Day, the publisher's direct shop six days later. The gap was not laziness: Amazon arithmetic (60% above threshold, 40-50% net), the German Buchpreisbindungsgesetz (one fixed price for everyone, the publisher included), the One-Stop-Shop quarterly tax window (filed April, effective 1 July), and Stripe's merchant geography. Hardcover 90 EUR, paperback 80 EUR, hand-signed direct. PDF and ePub 40 EUR each, direct-only." },
    { date = "Tue, 28 Apr 2026 00:00:00 GMT", title = "pf", loc = "/blog/pf", desc = "In May 2001 OpenBSD pulled IPFilter out of the source tree over a licence dispute. Daniel Hartmeier, who had never written kernel code, replaced it in twenty-five days. By 1 December 2001 it shipped in OpenBSD 3.0. Twenty-five years on, pf is the firewall in OpenBSD, FreeBSD, NetBSD, DragonFly and macOS, runs on roughly a billion Apple devices, and Linux's nftables (2014) is rather quietly an admission that pf had the right shape." },
    { date = "Mon, 27 Apr 2026 00:00:00 GMT", title = "What the Bootloader Knows", loc = "/blog/what-the-bootloader-knows", desc = "Between firmware that knows almost nothing and a kernel that must know everything sits a small program with a strange job. FreeBSD loader: ~600 KB Forth, ZFS-aware Boot Environment menu. LILO (1992-2015): block lists. GRUB 2: an operating system before the operating system. Three theories of the OS." },
    { date = "Sun, 26 Apr 2026 00:00:00 GMT", title = "Why We Measure Tickets, Not Problems Prevented", loc = "/blog/why-we-measure-tickets", desc = "The dashboard is green. Production has been quietly fragile for eleven weeks. Taylor 1911, Goodhart 1975, Strathern 1997, Jeffries 2019: we were warned by name. The engineer who prevents three outages closes zero tickets and is invisible. The one who closes forty-seven is promoted. The chair, somewhere, is not being built." },
    { date = "Sat, 25 Apr 2026 00:00:00 GMT", title = "The Dependency Avalanche", loc = "/blog/dependency-avalanche", desc = "Express resolves 65 packages, 3.6 MB. Next.js (create-next-app defaults) resolves 644 packages, 463 MB, to render eighteen characters of text. XZ CVE-2024-3094: 2.5 years of patient social engineering against an unpaid maintainer, caught by Andres Freund noticing 500 ms of SSH latency. Next time it might be 50." },
    { date = "Fri, 24 Apr 2026 00:00:00 GMT", title = "Service Mesh: The Sidecar Tax", loc = "/blog/service-mesh-sidecar-tax", desc = "mTLS, observability, zero-code retries. Splendid. CNCF 2024 Survey: mesh adoption 42%, down from 50%. 2025 peer-reviewed benchmark: Istio sidecar +166% mTLS latency, Linkerd +33%, Istio Ambient +8%. 60 MB RAM per pod, 60 GB across a 1,000-pod cluster before code runs. Ambient is Istio's own admission." },
    { date = "Thu, 23 Apr 2026 00:00:00 GMT", title = "Integrated by Design — Launch Day", loc = "/blog/integrated-by-design-launch", desc = "Launch day for Integrated by Design, 371 pages on FreeBSD, on UNESCO World Book Day. Five months of writing, three weeks of final proofs, then 72 hours of the problems one does not anticipate: one unclosed counter on the number 8, invisible adjustment layers in a cover PDF, a KDP form that says list price and means net, a Kindle in Amazon's review queue." },
    { date = "Wed, 22 Apr 2026 00:00:00 GMT", title = "The CSS Scope You Never Had to Compile", loc = "/blog/css-scope", desc = "Every web developer has fought this fight: .card h3 colliding with a third-party widget. BEM, CSS Modules, 80 KB of styled-components. @scope is the native answer: zero specificity, a new cascade tier called scoping proximity, cross-browser stable since December 2025. The cascade, after twenty-five years, is finally finished." },
    { date = "Tue, 21 Apr 2026 00:00:00 GMT", title = "Markdown", loc = "/blog/markdown", desc = "On 15 March 2004, John Gruber posted a blog entry and a 1,400-line Perl script. Aaron Swartz was the sole beta-tester. No lexer, no parser, no AST. Twenty-one years later, GitHub, Reddit, Notion, and every major LLM speak Markdown. Third year running as the most admired documentation format. Plain text won." },
    { date = "Mon, 20 Apr 2026 00:00:00 GMT", title = "The Snapshot That Travels", loc = "/blog/the-snapshot-that-travels", desc = "At 3 AM on a production cluster measured in terabytes, the question is whether any of your backup tools will finish before breakfast. ZFS snapshot, send, clone: atomic in milliseconds, 40 TB delta in seconds, copy-on-write branches at zero cost. Backup, replication, and branching are three uses of the same primitive." },
    { date = "Sun, 19 Apr 2026 00:00:00 GMT", title = "Why We Accepted Surveillance as Default", loc = "/blog/why-we-accepted-surveillance", desc = "In January 1996, two men in New York founded DoubleClick. Nobody voted on this. 7 trackers per page, 600 billion bid requests per day, 90% accept when Reject all is hidden. Apple ATT 2021: one OS prompt, -$10B Meta revenue. The technology was always there." },
    { date = "Sat, 18 Apr 2026 00:00:00 GMT", title = "The Compute-Is-Cheap Decade", loc = "/blog/compute-is-cheap-decade", desc = "Knuth's quote was 97%/3%. Only the 97% survived. Discord rewrote Go in Rust: memory down 40%, latency 160x. Twitter decommissioned 148,000 servers and continued to function. WhatsApp 2015: fifty engineers for 900 million users. Data centres: 415 TWh in 2024, 945 TWh projected by 2030." },
    { date = "Fri, 17 Apr 2026 00:00:00 GMT", title = "Auth0: The Identity Tax", loc = "/blog/auth0-identity-tax", desc = "Okta paid $6.5B for a company doing $200M in revenue. The arithmetic suggests the customer pays the difference. 300% per-MAU hike in one announcement. Two breaches, every customer's name and email exfiltrated. The password hash was always there." },
    { date = "Thu, 16 Apr 2026 00:00:00 GMT", title = "Redis: The One-Thread Design", loc = "/blog/redis-single-thread", desc = "In 2009, Salvatore Sanfilippo made Redis single-threaded. A contested mutex costs 10,000 CPU cycles. Redis makes contention structurally impossible. 1.5 million operations per second, one core, commodity hardware. The limitation is the architecture. The architecture is the feature." },
    { date = "Wed, 15 Apr 2026 00:00:00 GMT", title = "The Deep Clone You Never Had to Install", loc = "/blog/structured-clone", desc = "JSON.parse(JSON.stringify()) destroys Date, Map, Set, RegExp, and throws on circular references. structuredClone handles all of them. Zero KB. Built in since 2022. Lodash cloneDeep: 17 KB, unchanged for a decade." },
    { date = "Tue, 14 Apr 2026 00:00:00 GMT", title = "ssh-agent", loc = "/blog/ssh-agent", desc = "2,624 lines of C. One file. One socket. No config. The private key never leaves the process. Born from impatience in 1995, designed with discipline, still the authentication backbone of every CI/CD system on earth." },
    { date = "Mon, 13 Apr 2026 00:00:00 GMT", title = "periodic", loc = "/blog/periodic", desc = "cron tells you when. periodic tells you what happened. FreeBSD: one config file, severity-coded output, daily email. OpenBSD: pledge/unveil violation reports. Linux: twenty files for ten tasks. The problem was never scheduling. It was accountability." },
    { date = "Sun, 12 Apr 2026 00:00:00 GMT", title = "Why the Cloud Is the Default", loc = "/blog/why-the-cloud-is-the-default", desc = "27% of cloud spend wasted ($182B/year). 37signals saved $10M+ leaving AWS. Ahrefs: 11.3x cheaper on-prem. 86% of CIOs plan repatriation. The cloud was the only answer nobody got fired for choosing." },
    { date = "Sat, 11 Apr 2026 00:00:00 GMT", title = "The Feature Creep", loc = "/blog/the-feature-creep", desc = "Notion: notes to email client. Jira: bug tracker to 3,000 plugins. Google: 299 products killed. Sonos: CEO resigned. Skype: 405M to shutdown. VLC: media player since 2001. The best software never added the wrong features." },
    { date = "Fri, 10 Apr 2026 00:00:00 GMT", title = "The Certification Industrial Complex", loc = "/blog/certification-industrial-complex", desc = "$700 exam. Expires in 3 years. Repeat. Non-certified skills earn 2% more since 2007. CompTIA: $168M/year, now PE-owned. Kent Beck called it a pyramid scheme. When private equity acquires the exam, the product is you." },
    { date = "Thu, 09 Apr 2026 00:00:00 GMT", title = "Rust Says No", loc = "/blog/rust-says-no", desc = "No null. No exceptions. No garbage collector. No inheritance. In 2006, Graydon Hoare walked up 21 floors because his elevator crashed. Memory bug. C code. He started writing Rust. Every no eliminates a category of bugs. The elevator stops crashing." },
    { date = "Wed, 08 Apr 2026 00:00:00 GMT", title = "The Page Transition You Never Had to Build", loc = "/blog/view-transitions", desc = "We shipped 400KB of JavaScript so a heading could fade. The browser does it now. Three lines of CSS. Zero JavaScript. View Transition API: 0KB. 87.82% global coverage. Progressive enhancement, done properly." },
    { date = "Tue, 07 Apr 2026 00:00:00 GMT", title = "DTrace", loc = "/blog/dtrace", desc = "Zero overhead when probes are disabled. Safe by construction. Concise answers to arbitrary questions. DTrace solved production observability in 2003. FreeBSD ships it in base. Logging records what you predicted. DTrace answers what you never thought to ask." },
    { date = "Mon, 06 Apr 2026 00:00:00 GMT", title = "The Philosophy", loc = "/blog/the-unix-philosophy", desc = "In 1978, Doug McIlroy wrote four sentences. They have outlasted every framework since. Do one thing well. Text as universal interface. Silence is golden. FreeBSD, macOS, OpenBSD: the systems that follow the philosophy outlast the systems that ignore it." },
    { date = "Sun, 05 Apr 2026 00:00:00 GMT", title = "Why We Teach Tools Instead of Foundations", loc = "/blog/why-we-teach-tools", desc = "In the 1990s, CS taught foundations. In 2026, it teaches React. Alan Kay warned us in 2004. MIT proved him right in 2020. 250,000 Kubernetes certifications. One does wonder how many could explain what a process is." },
    { date = "Sun, 05 Apr 2026 00:00:00 GMT", title = "AI Code Generation: The Hallucination Tax", loc = "/blog/ai-code-generation", desc = "METR: developers 19% slower with AI (believed 20% faster). 19.6% of recommended packages do not exist. 40% of Copilot output contains vulnerabilities. Refactoring collapsed from 25% to under 10%. Write lean. The AI will follow." },
    { date = "Sat, 04 Apr 2026 00:00:00 GMT", title = "The Update Treadmill", loc = "/blog/the-update-treadmill", desc = "Your software worked on Friday. npm update broke it on Monday. Angular: 18 major versions in 10 years. 75% of dev time on maintenance. SQLite: backwards-compatible since 2004. The treadmill is not inevitable. It is profitable." },
    { date = "Fri, 03 Apr 2026 00:00:00 GMT", title = "JavaScript Backend: The Full-Stack Tax", loc = "/blog/javascript-backend", desc = "Built in ten days for form validation. Express: 20K RPS. Rust: 60K. Idle memory: 30-50 MB vs 1-2 MB. One thread. 500K malicious npm packages. The creator called node_modules an irreparable mistake and built Deno." },
    { date = "Thu, 02 Apr 2026 00:00:00 GMT", title = "CSV: The Format Nobody Designed", loc = "/blog/by-design-csv", desc = "In 1972, IBM separated values with commas. No specification. No committee. Thirty-three years later, someone wrote the RFC. 60% of enterprises still use CSV. The format that requires no agreement outlasts the format that requires consensus." },
    { date = "Wed, 01 Apr 2026 00:00:00 GMT", title = "The Native Popover That Positions Itself", loc = "/blog/popover-anchor", desc = "Floating UI: 35KB. Popper.js: 28KB. Tippy.js: 22KB. The native equivalent: zero kilobytes. The Popover API handles visibility, z-index, light dismiss, and keyboard. CSS Anchor Positioning handles placement and viewport flipping." },
    { date = "Tue, 31 Mar 2026 00:00:00 GMT", title = "Let's Encrypt", loc = "/blog/lets-encrypt", desc = "Before 2015, HTTPS was a luxury. A certificate cost $50 and a week of manual process. Then four people decided this was absurd. 700 million websites. 10 million certificates per day. Ten years. Zero pounds." },
    { date = "Mon, 30 Mar 2026 00:00:00 GMT", title = "The .env File Nobody Needs", loc = "/blog/the-env-file", desc = "107 million weekly downloads for dotenv. A package that reads KEY=VALUE pairs from a file. Unix has done this since 1979. GitHub detected 39 million leaked secrets in 2024. Even Node.js shipped --env-file natively." },
    { date = "Sun, 29 Mar 2026 00:00:00 GMT", title = "Google Search: The Time Tax", loc = "/blog/search-quality", desc = "30% of a knowledge worker's day spent searching. Google's trust score dropped from 7.05 to 5.73 in one year. 83% zero-click rate with AI Overviews. The search engine that once finished your sentence now wastes your afternoon." },
    { date = "Sat, 28 Mar 2026 00:00:00 GMT", title = "The Quality Erosion", loc = "/blog/the-quality-erosion", desc = "In 2023, Klarna replaced 700 support agents with AI. Costs down 25%. In 2025, they started rehiring humans. 64% of customers prefer no AI in support. 41% higher code churn. 19% slower with AI tools. The tool is neutral. The incentive is not." },
    { date = "Fri, 27 Mar 2026 00:00:00 GMT", title = "qq", loc = "/blog/bytes-of-art-qq", desc = "64 kilobytes. Three minutes of architectural hallucination by Quite. Corridors fold into corridors. Every frame calculated in real time from a single executable built with Werkkzeug1. First place at DiHALT 2012." },
    { date = "Fri, 27 Mar 2026 00:00:00 GMT", title = "GraphQL: The Query Tax", loc = "/blog/graphql", desc = "In 2012, Facebook had a problem: hundreds of microservices, a mobile News Feed, constrained bandwidth. They built GraphQL. The solution was brilliant. For Facebook. You have 12 REST endpoints and a fetch() call." },
    { date = "Thu, 26 Mar 2026 00:00:00 GMT", title = "The Single Writer", loc = "/blog/by-design-sqlite", desc = "In 2000, D. Richard Hipp built a database for a U.S. Navy destroyer. The existing Informix installation required a DBA. Hipp's solution was not to fix the server. It was to eliminate it entirely. 600 KB. One file. Zero configuration. The most deployed software module in history." },
    { date = "Tue, 25 Mar 2026 00:00:00 GMT", title = "Server-Sent Events", loc = "/blog/sse", desc = "Most real-time features are one-way. The browser solved this in 2015 with one line of JavaScript that nobody teaches. No npm. No reconnect logic. EventSource reconnects automatically. The specification demands it." },
    { date = "Tue, 24 Mar 2026 00:00:00 GMT", title = "vi", loc = "/blog/vi", desc = "2.7 million people have visited Stack Overflow to learn how to exit a text editor. The most feared tool in computing is also the most elegant. A composable grammar born from a 300 baud modem. Fifty years of production." },
    { date = "Mon, 23 Mar 2026 00:00:00 GMT", title = "The Log", loc = "/blog/the-log", desc = "Eric Allman wrote syslog in the 1980s. Forty years of production. Zero licence fees. Log rotation, live monitoring, frequency analysis, and alerting. Four commands. Each composable. Each free." },
    { date = "Sun, 22 Mar 2026 00:00:00 GMT", title = "Why Mathematicians Design Languages", loc = "/blog/why-mathematicians-design-languages", desc = "Every mainstream programming language was designed by a mathematician. Not one linguist in the room. Ninety years later, we are still writing in their notation. One does wonder what might have happened if someone had invited one." },
    { date = "Sun, 22 Mar 2026 00:00:00 GMT", title = "The Observability Tax", loc = "/blog/the-observability-tax", desc = "syslog has existed since 1983. In 2026, a mid-sized company spends $708,000 per year to know whether its servers are running. 97% report cost surprises. The watchtower now costs more than the castle." },
    { date = "Sat, 21 Mar 2026 00:00:00 GMT", title = "The Electron Tax", loc = "/blog/the-electron-tax", desc = "Every Electron app ships its own copy of Chromium. Slack, Discord, Teams, VS Code. Four apps, four browsers, none displaying a web page. The company saves on engineering. The user pays in RAM, battery, and disk space." },
    { date = "Fri, 20 Mar 2026 00:00:00 GMT", title = "Terraform: The Abstraction Layer", loc = "/blog/terraform", desc = "You wanted to provision a server. You got a proprietary language that cannot express a conditional, a state file that stores your secrets in plain text, and a licence that changed overnight. Three invoices for one abstraction." },
    { date = "Thu, 19 Mar 2026 00:00:00 GMT", title = "Hydration", loc = "/blog/hydration", desc = "In 1995, PHP rendered HTML on the server. In 2026, the industry renders HTML on the server, then ships 558 KB of JavaScript to rebuild the same DOM. They call this hydration. Twenty years to return to where PHP started." },
    { date = "Wed, 18 Mar 2026 00:00:00 GMT", title = "The Form the Browser Already Validated", loc = "/blog/form-validation", desc = "The average React project installs a validation library before a single input field exists. The browser has validated forms natively since 2014. Required, email, pattern, minlength. No JavaScript. No bundle size." },
    { date = "Tue, 17 Mar 2026 00:00:00 GMT", title = "The Pipe", loc = "/blog/the-pipe", desc = "In 1964, Douglas McIlroy wrote a memo about coupling programmes like garden hose. Nine years later, Ken Thompson implemented it overnight. One character. The most elegant composition model in computing, fifty-three years unchanged." },
    { date = "Mon, 16 Mar 2026 00:00:00 GMT", title = "The Origin", loc = "/blog/the-unix-origins", desc = "In 1969, Ken Thompson wanted to play Space Travel. The mainframe cost $75 per session. So he found a PDP-7 with 9 KB of memory and built an operating system. Its descendants run most of the world." },
    { date = "Sun, 15 Mar 2026 00:00:00 GMT", title = "The Next.js Tax", loc = "/blog/the-nextjs-tax", desc = "React ships 136 KB to the browser. Next.js promised to fix that. 247 MB of node_modules, 87 KB client runtime, hydration that doubles every render, and vendor lock-in disguised as developer experience." },
    { date = "Sat, 14 Mar 2026 00:00:00 GMT", title = "The Early Access Alibi", loc = "/blog/the-early-access-alibi", desc = "Early access was invented so a solo developer in Stockholm could finish a game about mining blocks. Then publishers noticed. They copied the label. Not the honesty. 25,000 jobs lost at record revenue." },
    { date = "Fri, 13 Mar 2026 00:00:00 GMT", title = "Jira: The Workflow Tax", loc = "/blog/jira", desc = "You wanted to track bugs. You got a bureaucracy engine with custom fields nobody remembers creating and workflows nobody dares to simplify. 68% of new users overwhelmed. 1-4 seconds per issue. 883 sites deleted. The Jira invoice, itemised." },
    { date = "Thu, 12 Mar 2026 00:00:00 GMT", title = "Clean Code: The Prescription That Outlived the Diagnosis", loc = "/blog/clean-code", desc = "Robert C. Martin published Clean Code in 2008 to fix Java enterprise monoliths with no structure. The industry copied the rules and forgot the context. A prescription without a diagnosis." },
    { date = "Wed, 11 Mar 2026 00:00:00 GMT", title = "Bytes of Art: 0mix", loc = "/blog/bytes-of-art-0mix", desc = "64 kilobytes. A seven-minute techno live set with procedural visuals and synthesised audio, running in your browser. Won Best Soundtrack at The Meteoriks 2024 against every production of the year." },
    { date = "Wed, 11 Mar 2026 00:00:00 GMT", title = "Native WebSocket: Server Pushes, Client Listens", loc = "/blog/websocket", desc = "Your frontend needs live data. React taught an entire generation of developers to poll. The browser solved this in 2011 with two lines of JavaScript and zero npm packages." },
    { date = "Mon, 10 Mar 2026 00:00:00 GMT", title = "diff: The Tool That Enabled Collaboration", loc = "/blog/technical-beauty-diff", desc = "In 1974, James Hunt and Douglas McIlroy built diff at Bell Labs. Two files in, one output: what changed. Every code review, every pull request, every version control system since RCS stores history as diffs. 52 years in production. No subscription." },
    { date = "Sun, 09 Mar 2026 00:00:00 GMT", title = "SSH Config: The File Nobody Reads", loc = "/blog/ssh-config", desc = "You type ssh -i ~/.ssh/prod_key -p 2222 deploy@192.168.50.12 fourteen times a day. There is a plain text file that reduces this to ssh prod. It has existed since 1999. One file. No GUI. No subscription." },
    { date = "Sat, 08 Mar 2026 00:00:00 GMT", title = "The Distributed Tax", loc = "/blog/the-distributed-tax", desc = "A function call costs 0.001 ms. A network call between two microservices costs 1 to 5 ms. That is factor 5,000 before any business logic executes." },
    { date = "Fri, 07 Mar 2026 00:00:00 GMT", title = "The Enshittification Cycle", loc = "/blog/the-enshittification-cycle", desc = "Cory Doctorow named it. You have lived it. Every platform begins by being useful, then monetises its users, then monetises its business customers, then dies." },
    { date = "Thu, 06 Mar 2026 00:00:00 GMT", title = "Rolling Releases: The Perpetual Beta", loc = "/blog/rolling-releases", desc = "Software used to ship when it was ready. Now it ships when the sprint ends. Chrome halved its release cycle twice. CrowdStrike pushed one update and crashed 8.5 million machines." },
    { date = "Wed, 05 Mar 2026 00:00:00 GMT", title = "BEM: The Naming Convention That Named Itself Indispensable", loc = "/blog/bem", desc = "BEM was invented at Yandex to stop CSS from breaking across 100 services. The industry adopted it to name twelve classes on a landing page." },
    { date = "Tue, 04 Mar 2026 00:00:00 GMT", title = "The Server Question", loc = "/blog/the-server-question", desc = "72% of the web runs on PHP. Not an accident. But the web has moved: persistent connections, live pushes, minimal memory. Five languages, one task, a 128x difference in memory." },
    { date = "Mon, 03 Mar 2026 00:00:00 GMT", title = "Technical Beauty: jq", loc = "/blog/technical-beauty-jq", desc = "In 2012, JSON was the lingua franca of the web and the Unix toolbox had nothing for it. One PhD student at Cambridge wrote a functional language in 510 KB of C." },
    { date = "Sun, 02 Mar 2026 00:00:00 GMT", title = "Capsicum vs seccomp: Process Sandboxing", loc = "/blog/capsicum-vs-seccomp", desc = "A compromised process inherits the full authority of the user who launched it. Two operating systems fixed this with opposite philosophies." },
    { date = "Sat, 01 Mar 2026 00:00:00 GMT", title = "GraphQL: The Query You Didn't Need", loc = "/blog/the-graphql-tax", desc = "GraphQL was built at Facebook for the News Feed. REST is 50% faster on relational databases. 34x faster with eager loading. The performance tax, itemised." },
    { date = "Sat, 28 Feb 2026 00:00:00 GMT", title = "The Permanent Beta", loc = "/blog/the-permanent-beta", desc = "Software used to come on a disc. A bug on a pressed CD was a recall, not a hotfix. Then the internet removed the disc." },
    { date = "Fri, 27 Feb 2026 00:00:00 GMT", title = "SaaS: The Subscription Tax", loc = "/blog/the-saas-tax", desc = "In 2012, you could buy Adobe Creative Suite for $2,599. You owned it. In 2026, you pay $660 per year and own nothing." },
    { date = "Thu, 26 Feb 2026 00:00:00 GMT", title = "The Kernel Question", loc = "/blog/the-kernel-question", desc = "Europe wants digital sovereignty but builds on a kernel governed by US corporations. 84.3% of Linux commits, $500K board seats." },
    { date = "Thu, 26 Feb 2026 00:00:00 GMT", title = "Containerise Everything", loc = "/blog/containerise-everything", desc = "Docker solved deployment. Then the industry decided it also solved development. On macOS, that means running a Linux VM to execute a process that runs natively." },
    { date = "Wed, 25 Feb 2026 00:00:00 GMT", title = "CSS Learns to Think", loc = "/blog/css-learns-to-think", desc = "For twenty-three years, CSS could only look downward. A parent styled its children. Never the reverse. In 2023, three pseudo-classes changed the direction of the cascade." },
    { date = "Wed, 25 Feb 2026 00:00:00 GMT", title = "Why Every Byte Matters", loc = "/blog/why-every-byte-matters", desc = "The demoscene taught a generation that constraint is not limitation; it is method. Every instruction must justify its presence." },
    { date = "Tue, 24 Feb 2026 00:00:00 GMT", title = "make: Three Concepts, Fifty Years", loc = "/blog/technical-beauty-make", desc = "1976. Stuart Feldman writes make in a weekend. Targets, dependencies, timestamps. Three concepts. Fifty years. Same algorithm." },
    { date = "Mon, 23 Feb 2026 00:00:00 GMT", title = "The Original Microservices", loc = "/blog/the-original-microservices", desc = "Unix had single responsibility, API contracts, message queues, and service discovery in 1973. The industry repackaged it and called it microservices." },
    { date = "Sun, 22 Feb 2026 00:00:00 GMT", title = "JavaScript Bloat: The Battery Tax", loc = "/blog/the-javascript-tax", desc = "558 KB median JavaScript per page. 44 per cent never executes. Mobile parses 25x slower than your dev machine." },
    { date = "Sat, 21 Feb 2026 00:00:00 GMT", title = "Markdown: The File That Outlives the Company", loc = "/blog/the-markdown-replacement", desc = "John Gruber wrote the specification in 2004. A Perl script. 1,122 lines. Twenty-two years later, the format has not changed. It is text. Your Confluence export has already lost its macros." },
    { date = "Fri, 20 Feb 2026 00:00:00 GMT", title = "The Scrum Tax", loc = "/blog/the-scrum-tax", desc = "Six developers, 80 hours of sprint, 18 hours of ceremonies. A Scrum Master who costs $126k and requires no technical prerequisites." },
    { date = "Wed, 18 Feb 2026 00:00:00 GMT", title = "HTML Dialog: Modal or Not Modal", loc = "/blog/the-dialog-element", desc = "22.5 million npm installs per week for JavaScript that recreates the native dialog element. Focus traps, escape handlers, backdrop overlays. Every browser ships it. Since 2022." },
    { date = "Wed, 18 Feb 2026 00:00:00 GMT", title = "Bytes of Art: Neuron Activated", loc = "/blog/bytes-of-art-neuron-activated", desc = "5 kilobytes. One person. First place. Krzysztof Kluczek wrote the code, designed the visuals, and built a guitar synthesiser at Riverwash 2014." },
    { date = "Tue, 17 Feb 2026 00:00:00 GMT", title = "Technical Beauty: sed", loc = "/blog/technical-beauty-sed", desc = "A psychologist at Bell Labs writes a text editor that never opens a file. 53 years later, it runs everywhere. 25 commands, two buffers, one pass." },
    { date = "Mon, 16 Feb 2026 00:00:00 GMT", title = "Service Management: init vs systemd", loc = "/blog/init-vs-systemd", desc = "FreeBSD init runs on 178 shell scripts and one shared library. systemd ships 690,000 lines of C across 150 compiled binaries." },
    { date = "Sun, 15 Feb 2026 00:00:00 GMT", title = "The Webpack Tax", loc = "/blog/the-webpack-tax", desc = "Webpack solved a 2012 problem that ES Modules natively solved in 2017. esbuild is 106x faster. Vite cold-starts in 1.7 seconds." },
    { date = "Fri, 13 Feb 2026 00:00:00 GMT", title = "MongoDB: The Reinvention of the Wheel", loc = "/blog/the-mongodb-tax", desc = "MongoDB stores relational data in a document store, then spends a decade rebuilding the relational features it discarded." },
    { date = "Thu, 12 Feb 2026 00:00:00 GMT", title = "Unit Tests for Everything", loc = "/blog/unit-tests-for-everything", desc = "In 1994, Kent Beck wrote SUnit to test isolated units of logic. By 2015, the industry had turned his invention into a coverage KPI." },
    { date = "Wed, 11 Feb 2026 00:00:00 GMT", title = "The Specificity War Is Over", loc = "/blog/the-specificity-war", desc = "CSS Cascade Layers end the two-decade specificity war permanently. One declaration line sets the hierarchy. Layer order outranks specificity." },
    { date = "Tue, 10 Feb 2026 00:00:00 GMT", title = "mc: The Workstation in 12 MB", loc = "/blog/technical-beauty-mc", desc = "In 1994, a computer science student in Mexico City wrote a file manager. 31 years later, it runs on anything with a C compiler. 220,000 lines of C. 12 MB of RAM. Dual panels, built-in editor, FTP, SFTP, archive browsing. No venture capital." },
    { date = "Tue, 10 Feb 2026 00:00:00 GMT", title = "HTTP/2: The Bundling Myth", loc = "/blog/http2-the-bundling-myth", desc = "HTTP/1.1 made bundling necessary. HTTP/2 made it obsolete. Multiplexing, granular caching, and the rule that inverted itself a decade ago." },
    { date = "Mon, 09 Feb 2026 00:00:00 GMT", title = "ZFS Snapshots &amp; Boot Environments: The Safety Net", loc = "/blog/zfs-the-safety-net", desc = "Same ZFS, same commands, radically different experience. On FreeBSD, bectl is in base, the bootloader understands boot environments natively." },
    { date = "Mon, 09 Feb 2026 00:00:00 GMT", title = "ZFS Snapshots: Same Commands, Different Experience", loc = "/blog/zfs-snapshots", desc = "The ZFS commands are identical on FreeBSD and Linux. The snapshots work the same way. The difference is everything around them: kernel integration, boot environments, and what happens when you upgrade." },
    { date = "Sun, 08 Feb 2026 00:00:00 GMT", title = "Kubernetes: You Are Not Google", loc = "/blog/the-kubernetes-performance-tax", desc = "82 per cent of container users run Kubernetes in production. The control plane demands 12-24 GB RAM before your app serves one request." },
    { date = "Sun, 08 Feb 2026 00:00:00 GMT", title = "The Interpreted Stack", loc = "/blog/the-interpreted-stack", desc = "The job description is admirably brief: a request arrives, HTML leaves. And yet, a quarter century of accretion has produced something rather more elaborate." },
    { date = "Sat, 07 Feb 2026 00:00:00 GMT", title = "ORM: The Illusion of Portability", loc = "/blog/the-orm-illusion", desc = "ORMs hide complexity instead of eliminating it. They promise database portability you will never use and obscure queries you should understand." },
    { date = "Fri, 06 Feb 2026 00:00:00 GMT", title = "Docker: The Capitulation", loc = "/blog/the-docker-tax", desc = "Docker did not solve a technical problem. It monetised a political one. Linux could not agree on a base system, so the industry shipped the entire OS with every application." },
    { date = "Thu, 05 Feb 2026 00:00:00 GMT", title = "READS: The Five Prefixes", loc = "/blog/reads-the-five-prefixes", desc = "OOCSS arrived in 2009. BEM arrived in 2010. Both produce identical specificity. One reads like a sentence. The other reads like a German compound noun." },
    { date = "Thu, 05 Feb 2026 00:00:00 GMT", title = "MVC for Web", loc = "/blog/mvc-for-web", desc = "In 1979, Trygve Reenskaug invented MVC for Smalltalk desktop applications. Then Ruby on Rails borrowed the terminology for the web." },
    { date = "Wed, 04 Feb 2026 00:00:00 GMT", title = "Technical Beauty: Redis", loc = "/blog/technical-beauty-redis", desc = "Salvatore Sanfilippo built Redis in 2009. Single-threaded by design. One event loop, no locks. 100,000+ operations per second on modest hardware." },
    { date = "Mon, 03 Feb 2026 00:00:00 GMT", title = "man: Read the Manual. It's Already Installed.", loc = "/blog/technical-beauty-man", desc = "Ken Thompson wrote the first man pages for Unix Version 1 in 1971. Fifty-five years later, the format remains. One structure. Every tool. Always. Offline documentation that matches the version you are actually running." },
    { date = "Sun, 01 Feb 2026 00:00:00 GMT", title = "Technical Beauty: ZFS", loc = "/blog/technical-beauty-zfs", desc = "Jeff Bonwick and Matthew Ahrens built ZFS at Sun Microsystems in 2005. Filesystems trusted hardware that lies. ZFS trusts mathematics instead." },
    { date = "Sun, 01 Feb 2026 00:00:00 GMT", title = "Technical Beauty: OpenSSH", loc = "/blog/technical-beauty-openssh", desc = "Theo de Raadt forked SSH in 1999. The original was accumulating licence restrictions. OpenSSH stripped it down, audited everything, and assumed the network is hostile." },
    { date = "Sun, 01 Feb 2026 00:00:00 GMT", title = "Team Autonomy: The Balkanisation", loc = "/blog/the-balkanisation", desc = "Four teams, four frameworks, four pipelines, four security postures. A cross-team feature ships in month three." },
    { date = "Sun, 01 Feb 2026 00:00:00 GMT", title = "The Framework Tax", loc = "/blog/the-framework-tax", desc = "In 2010, vanilla JavaScript built the web. In 2026, a React Hello World installs 2,839 packages." },
    { date = "Sat, 31 Jan 2026 00:00:00 GMT", title = "From REST Ceremony to JSON-RPC", loc = "/blog/the-json-rpc-replacement", desc = "Five HTTP verbs. Fifty status codes. URL hierarchies. Content negotiation. All to answer: client wants something from server. JSON-RPC answered that in 2005." },
    { date = "Fri, 30 Jan 2026 00:00:00 GMT", title = "Serverless: What You Actually Pay", loc = "/blog/the-serverless-tax", desc = "Serverless is not serverless. It is MicroVMs with amnesia, vendor lock-in with four incompatible dialects, and cold starts." },
    { date = "Fri, 30 Jan 2026 00:00:00 GMT", title = "Technical Beauty: rsync", loc = "/blog/technical-beauty-rsync", desc = "Andrew Tridgell had a problem in 1996: synchronising files over slow links. rsync splits files into chunks, computes rolling checksums, and transfers only the differences." },
    { date = "Thu, 29 Jan 2026 00:00:00 GMT", title = "Technical Beauty: FFmpeg", loc = "/blog/technical-beauty-ffmpeg", desc = "Fabrice Bellard started FFmpeg in 2000. The multimedia world was fragmented. FFmpeg handles every format ever created. 1.5 million lines of C." },
    { date = "Thu, 29 Jan 2026 00:00:00 GMT", title = "Technical Beauty: tar", loc = "/blog/technical-beauty-tar", desc = "1979. John Gilmore writes tar for Unix V7. Tape ARchive. One format, one purpose: bundle files into a stream. Every container image is a stack of tarballs." },
    { date = "Thu, 29 Jan 2026 00:00:00 GMT", title = "OKLCH: The Colour System That Does Not Lie", loc = "/blog/oklch-colour-system", desc = "For three decades, CSS lied about lightness. HEX told you nothing. HSL promised perceptual uniformity and delivered optical illusion. OKLCH fixes the problem." },
    { date = "Wed, 28 Jan 2026 00:00:00 GMT", title = "Technical Beauty: tmux", loc = "/blog/technical-beauty-tmux", desc = "Nicholas Marriott wrote tmux in 2007 because GNU Screen had accumulated three decades of cruft. BSD-licensed. 60,000 lines of C." },
    { date = "Wed, 28 Jan 2026 00:00:00 GMT", title = "The Replacement: FreeBSD Jails", loc = "/blog/the-jails-replacement", desc = "Docker needs a daemon, image layers, a registry, overlay networks. FreeBSD Jails need a directory and a config file. Native kernel isolation since 2000." },
    { date = "Tue, 27 Jan 2026 00:00:00 GMT", title = "From PHP to Rust: Why I Skipped Go", loc = "/blog/the-rust-replacement", desc = "After 20 years of PHP, I needed something new. Everyone said Go. I chose Rust instead. The compiler is your private tutor." },
    { date = "Tue, 27 Jan 2026 00:00:00 GMT", title = "pf vs nftables: Bruteforce", loc = "/blog/pf-vs-nftables", desc = "Fresh server, SSH open, auth.log fills up. Linux reaches for fail2ban, a Python daemon that parses logs after the fact. FreeBSD solves it in four lines of pf.conf." },
    { date = "Mon, 26 Jan 2026 00:00:00 GMT", title = "The Linux Compatibility Layer", loc = "/blog/the-linux-compatibility-layer", desc = "FreeBSD runs Linux binaries natively. No emulator. No VM. No container. The kernel translates syscalls in real time, at less than 1% overhead. Since 1995." },
    { date = "Sat, 25 Jan 2026 00:00:00 GMT", title = "SSH + Shell: The Configuration Management You Already Have", loc = "/blog/the-ssh-shell-replacement", desc = "Ansible solves a problem that SSH, a for loop, and configs in git solved twenty years earlier. For five servers, you do not need a framework. You need a shell script." },
    { date = "Sun, 25 Jan 2026 00:00:00 GMT", title = "TypeScript: The Build Tax", loc = "/blog/typescript-the-build-tax", desc = "ECMAScript is a complete language. Types are not missing from JavaScript: they were never part of the specification." },
    { date = "Sat, 24 Jan 2026 00:00:00 GMT", title = "CI/CD Pipelines: What You Actually Pay", loc = "/blog/the-cicd-tax", desc = "45-minute pipelines, 20 per cent of the work week lost to YAML, and a supply chain that leaked 23,000 repositories of secrets." },
    { date = "Fri, 23 Jan 2026 00:00:00 GMT", title = "Technical Beauty: Lua", loc = "/blog/technical-beauty-lua", desc = "25,000 lines of C. A 200 KB binary. Embedded in World of Warcraft, Lightroom, nginx, Redis, Neovim, Roblox, Nmap. Born from Brazilian trade barriers." },
    { date = "Thu, 22 Jan 2026 00:00:00 GMT", title = "Bytes of Art: Prelude to Neobyte", loc = "/blog/bytes-of-art-prelude-to-neobyte", desc = "240 by 136 pixels. 16 colours. 4 audio channels. TIC-80 deliberately mimics 1980s hardware. Spectrox squeezed voxel landscapes and copper bar effects out of those constraints. Second place at Deadline Berlin 2025." },
    { date = "Tue, 20 Jan 2026 00:00:00 GMT", title = "Technical Beauty: awk", loc = "/blog/technical-beauty-awk", desc = "Aho, Weinberger, Kernighan. 1977. A pattern-action language for text processing. One pass through the data. No compilation." },
    { date = "Mon, 19 Jan 2026 00:00:00 GMT", title = "The Pattern", loc = "/blog/the-pattern", desc = "Over eight episodes we dissected individual performance problems. Stand back far enough and a shape emerges. The same shape, every time." },
    { date = "Sun, 18 Jan 2026 00:00:00 GMT", title = "Bytes of Art: Clean Slate", loc = "/blog/bytes-of-art-clean-slate", desc = "65,536 bytes. Three people. A real-time rendered film with physically-based rendering, volumetric lighting, procedural everything." },
    { date = "Sun, 18 Jan 2026 00:00:00 GMT", title = "The Monitoring Replacement", loc = "/blog/the-monitoring-replacement", desc = "Prometheus needs 2 GB RAM to monitor 10 services. The Unix shell has had monitoring since 1971: ps, top, vmstat, netstat." },
    { date = "Sat, 17 Jan 2026 00:00:00 GMT", title = "Event Sourcing: The Archaeology Tax", loc = "/blog/the-event-sourcing-tax", desc = "Complete audit trail! Time travel! A shopping cart with 10 items produces 13+ events. A 3 TB replay takes 10 hours." },
    { date = "Sat, 17 Jan 2026 00:00:00 GMT", title = "The SSH Replacement", loc = "/blog/the-ssh-replacement", desc = "SSH plus shell replaces Ansible, Python, YAML, Jinja2, inventory files, role dependencies, and Galaxy collections." },
    { date = "Thu, 15 Jan 2026 00:00:00 GMT", title = "Bytes of Art: The Scene Is Dead", loc = "/blog/bytes-of-art-scene-is-dead", desc = "Razor 1911, founded 1985. Their 2012 demo is 64 kilobytes of irony: CRT scanlines, Dubmood's soundtrack, and a running gag." },
    { date = "Wed, 14 Jan 2026 00:00:00 GMT", title = "The Ones I Can't Show You", loc = "/blog/technical-beauty-closed-source", desc = "Some of the most elegant systems ever built are behind closed doors. QNX fit a complete POSIX OS on a 1.44 MB floppy. BeOS had pervasive multithreading before anyone understood why. NeXTSTEP gave us the web browser and macOS." },
    { date = "Wed, 14 Jan 2026 00:00:00 GMT", title = "Agile Estimation Theatre", loc = "/blog/agile-estimation-theatre", desc = "Story points were invented to stop managers converting estimates into deadlines. Then the industry converted story points into deadlines." },
    { date = "Wed, 14 Jan 2026 00:00:00 GMT", title = "Native Form Validation: The Library You Never Needed", loc = "/blog/the-native-form", desc = "44 KB of JavaScript to accomplish what HTML does with five characters. The browser validates. Accessible by default. Since 2014." },
    { date = "Tue, 13 Jan 2026 00:00:00 GMT", title = "Technical Beauty: cron", loc = "/blog/technical-beauty-cron", desc = "One loop. One file. Every minute. Since 1975. Ken Thompson wrote the first version at Bell Labs. Paul Vixie rewrote it in 1987. 2,500 lines of C." },
    { date = "Mon, 12 Jan 2026 00:00:00 GMT", title = "Bytes of Art: Zetsubo", loc = "/blog/bytes-of-art-zetsubo", desc = "4,096 bytes. A complete audiovisual experience: procedural geometry, synthesised soundtrack, real-time rendering. Prismbeings, 2018." },
    { date = "Thu, 08 Jan 2026 00:00:00 GMT", title = "htop: 20 Years of Treating the Terminal as a Canvas", loc = "/blog/technical-beauty-htop", desc = "In 2004, Hisham Muhammad looked at top and saw a tool from 1984 pretending the terminal was still a teletype. One binary replaced an entire workflow: top, ps, grep, kill, renice, lsof. 12,000 lines of C. Zero configuration." },
    { date = "Fri, 09 Jan 2026 00:00:00 GMT", title = "The Cloud-Native Tax", loc = "/blog/the-cloud-native-tax", desc = "The bill is 47 pages and requires a FinOps specialist to decode. Netflix uses AWS for the back office. For video delivery: FreeBSD, jails, bare metal." },
    { date = "Wed, 07 Jan 2026 00:00:00 GMT", title = "Vanilla JS: The Framework You Already Have", loc = "/blog/vanilla-js-the-framework-you-have", desc = "React ships 142 KB before your code runs. The browser ships querySelector, addEventListener, Web Components, Proxy, and fetch. Zero kilobytes." },
    { date = "Wed, 07 Jan 2026 00:00:00 GMT", title = "Technical Beauty: age", loc = "/blog/technical-beauty-age", desc = "Filippo Valsorda wrote age because GPG had become unusable. One binary. One command to encrypt. One command to decrypt. No key servers, no web of trust." },
    { date = "Tue, 06 Jan 2026 00:00:00 GMT", title = "Technical Beauty: FreeBSD Jails", loc = "/blog/technical-beauty-jails", desc = "Poul-Henning Kamp built FreeBSD Jails in 1999. Kernel-level isolation, near-zero overhead. Stable API for 25 years. No daemon, no overlay network." },
    { date = "Mon, 05 Jan 2026 00:00:00 GMT", title = "The CSS-in-JS Tax", loc = "/blog/the-css-in-js-tax", desc = "CSS-in-JS is writing CSS in JavaScript to generate CSS. The runtime overhead, the 13 KB library tax, hydration roulette." },
    { date = "Sun, 04 Jan 2026 00:00:00 GMT", title = "Vanilla CSS: The Sass Replacement", loc = "/blog/the-sass-replacement", desc = "Sass was revolutionary in 2012. Variables, nesting, functions. In 2026, CSS does all of it natively. No build step. No node-sass conflicts." },
    { date = "Sat, 03 Jan 2026 00:00:00 GMT", title = "AI Agents Waste More Compute on Padding Than on Answers", loc = "/blog/ai-padding-waste", desc = "Defensive loops, trained hedging, three tool-calls where one would do. Data centres humming at full capacity. Not for answers. For comfort. The demoscene taught me: 4 KB leaves no space for bullshit." },
    { date = "Fri, 02 Jan 2026 00:00:00 GMT", title = "The npm Tax", loc = "/blog/the-npm-tax", desc = "That sentence has done more damage to software security than any zero-day exploit. It installs 1,400 packages before your kettle has boiled." },
    { date = "Wed, 31 Dec 2025 00:00:00 GMT", title = "The SPA Tax", loc = "/blog/the-spa-tax", desc = "We need a Single Page Application. A perfectly reasonable sentence, provided one does not ask the follow-up question." },
    { date = "Tue, 30 Dec 2025 00:00:00 GMT", title = "Technical Beauty: nginx", loc = "/blog/technical-beauty-nginx", desc = "Igor Sysoev built nginx in 2004 because Apache's thread-per-connection model was architecturally wrong. Event-driven, pure C, no framework." },
    { date = "Mon, 29 Dec 2025 00:00:00 GMT", title = "The Angular Tax", loc = "/blog/the-angular-tax", desc = "Angular is the SAP of frontend frameworks. Zone.js monkey-patches 30+ browser APIs, a Hello World ships 500 KB, and Google builds Angular but does not use it." },
    { date = "Sun, 28 Dec 2025 00:00:00 GMT", title = "Agile: The Hostile Takeover", loc = "/blog/agile-the-hostile-takeover", desc = "Divide and conquer. The oldest strategy of control. Fragment the opposition. Isolate the units. They call it Agile." },
    { date = "Sat, 27 Dec 2025 00:00:00 GMT", title = "The Kubernetes Tax", loc = "/blog/the-kubernetes-tax", desc = "81 resource types. 200 lines of YAML to replace one systemctl command. A platform team before your first customer." },
    { date = "Fri, 26 Dec 2025 00:00:00 GMT", title = "Technical Beauty: curl", loc = "/blog/technical-beauty-curl", desc = "Daniel Stenberg released curl in 1998. 26 years, zero breaking changes, one dependency: libc. Runs on 10+ billion devices." },
    { date = "Wed, 24 Dec 2025 00:00:00 GMT", title = "Technical Beauty: PostgreSQL", loc = "/blog/technical-beauty-postgresql", desc = "Michael Stonebraker built POSTGRES at Berkeley in 1986. Minimal core, everything extensible. 38 years, same BSD licence. No corporate owner." },
    { date = "Tue, 23 Dec 2025 00:00:00 GMT", title = "Technical Beauty: git", loc = "/blog/technical-beauty-git", desc = "Linus Torvalds built git in ten days. 10 MB, no server, no database, no dependencies beyond libc. Content-addressable, distributed, backwards compatible since 2005." },
    { date = "Mon, 22 Dec 2025 00:00:00 GMT", title = "The Flexbox Tax", loc = "/blog/the-flexbox-tax", desc = "Flexbox arrived to solve layout. Then the industry used it for everything. Twelve wrapper divs for a holy grail layout that CSS Grid solves in three lines." },
    { date = "Sun, 21 Dec 2025 00:00:00 GMT", title = "The Browser Is Not a JavaScript Runtime", loc = "/blog/javascript-overuse", desc = "80% of the JavaScript on modern websites solves problems that do not exist anymore. Accordions, modals, form validation, lazy loading. The browser ships all of it. Zero kilobytes." },
    { date = "Sat, 20 Dec 2025 00:00:00 GMT", title = "The Microservices Tax", loc = "/blog/the-microservices-tax", desc = "But deployments are cleaner! That sentence has launched more Kubernetes clusters than any legitimate scaling requirement." },
    { date = "Wed, 17 Dec 2025 00:00:00 GMT", title = "WireGuard: The VPN That Fits in Your Head", loc = "/blog/technical-beauty-wireguard", desc = "Jason Donenfeld built WireGuard in 4,000 lines of code. OpenVPN needs 100,000. Linus Torvalds called it a work of art." },
    { date = "Tue, 16 Dec 2025 00:00:00 GMT", title = "Technical Beauty: SQLite", loc = "/blog/technical-beauty-sqlite", desc = "D. Richard Hipp built SQLite in 2000 for a US Navy destroyer. 600 KB, single file, zero configuration. Public domain. Supported until 2050." },
    { date = "Mon, 15 Dec 2025 00:00:00 GMT", title = "The React Tax", loc = "/blog/the-react-tax", desc = "React 18 ships 136 KB minified before you have written a single line of application code. The Virtual DOM costs 30 per cent versus vanilla JavaScript." },
    { date = "Sun, 14 Dec 2025 00:00:00 GMT", title = "Native ES Modules: The Replacement", loc = "/blog/the-esmodules-replacement", desc = "Browsers have understood ES Modules since 2018. HTTP/2 solved the request overhead in 2015. For 90% of projects, the build pipeline is the complexity." },
    { date = "Sun, 07 Dec 2025 00:00:00 GMT", title = "Shallow Errors", loc = "/blog/shallow-errors", desc = "In 2013, a German data scientist discovered Xerox scanners were silently changing numbers in scanned documents. No error. No warning." },
    { date = "Sun, 07 Dec 2025 00:00:00 GMT", title = "The Caddy Replacement", loc = "/blog/the-caddy-replacement", desc = "Caddy replaces Nginx, Certbot, Cron, and renewal hooks. One binary. Zero TLS configuration. Auto HTTPS since 2015." },
    { date = "Thu, 25 Dec 2024 00:00:00 GMT", title = "The Quiet Web", loc = "/blog/the-quiet-web", desc = "The web got far too loud. Pop-overs, cookie banners, newsletter modals, autoplay, scroll-jacking. The native dialog element and one preferences wizard replace every banner. Zero interruptions." },
    { date = "Wed, 18 Dec 2024 00:00:00 GMT", title = "The MVC Myth", loc = "/blog/the-mvc-myth", desc = "MVC was invented in 1979 for Smalltalk desktop GUIs. The web has no persistent controller, no event loop, no state between requests. 30% performance overhead from abstraction layers that serve no purpose in HTTP." },
}

local function escape(s)
    s = s:gsub("&", "&amp;")
    s = s:gsub("<", "&lt;")
    s = s:gsub(">", "&gt;")
    s = s:gsub("\"", "&quot;")
    s = s:gsub("'", "&apos;")
    return s
end

function route()
    local xml = '<?xml version="1.0" encoding="UTF-8"?>\n'
    xml = xml .. '<rss version="2.0" xmlns:atom="http://www.w3.org/2005/Atom">\n'
    xml = xml .. '<channel>\n'
    xml = xml .. '  <title>Vivian Voss</title>\n'
    xml = xml .. '  <link>' .. SITE .. '/blog</link>\n'
    xml = xml .. '  <description>Software architecture, Unix philosophy, and the demoscene. Selected articles by Vivian Voss.</description>\n'
    xml = xml .. '  <language>en-gb</language>\n'
    xml = xml .. '  <atom:link href="' .. SITE .. '/feed" rel="self" type="application/rss+xml"/>\n'

    for _, a in ipairs(articles) do
        xml = xml .. '  <item>\n'
        xml = xml .. '    <title>' .. escape(a.title) .. '</title>\n'
        xml = xml .. '    <link>' .. SITE .. a.loc .. '</link>\n'
        xml = xml .. '    <guid isPermaLink="true">' .. SITE .. a.loc .. '</guid>\n'
        xml = xml .. '    <pubDate>' .. a.date .. '</pubDate>\n'
        xml = xml .. '    <description>' .. escape(a.desc) .. '</description>\n'
        xml = xml .. '  </item>\n'
    end

    xml = xml .. '</channel>\n'
    xml = xml .. '</rss>\n'

    cn.res.header("Content-Type", "application/rss+xml; charset=utf-8")
    cn.res.header("Cache-Control", "public, max-age=3600")
    cn.res.body(xml)
end
